          : '精英'
      : '';

  // RAG 案例整理
  const casesText =
    cases.length > 0
      ? cases
          .map(
            (c, i) =>
              `案例${i + 1} [${c.age_group} ${c.class_level} ${c.month}] ${c.section}-${c.part}: ${c.method}（要点：${c.key_points}）`
          )
          .join('\n')
      : '';

  // 难度级别描述（U10三级版）
  const levelDesc = isU10
    ? `\n## U10级别说明（${levelLabel}）\n${u10LevelGuide[levelLabel] || ''}\n`
    : '';

  // 强度描述
  const intensityDesc: Record<string, string> = {
