              </h2>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                {players.map((player) => (
                  <button
                    key={player.id}
                    onClick={() => setSelectedPlayer(player)}
                    className={`p-4 rounded-xl text-center border-2 transition-all ${
                      selectedPlayer?.id === player.id
                        ? 'border-orange-500 bg-orange-50'
                        : 'border-gray-200 hover:border-gray-300'
                    }`}
                  >
                    <div className="w-12 h-12 rounded-full bg-gradient-to-br from-orange-400 to-yellow-400 flex items-center justify-center text-white font-bold mx-auto mb-2">
                      {player.name.charAt(0)}
                    </div>
                    <div className="font-medium text-gray-900">{player.name}</div>
                    <div className="text-xs text-gray-500">{player.group}</div>
                  </button>
                ))}
              </div>
            </div>

            {/* 步骤3：选择日期 */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
              <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
                <span className="w-6 h-6 bg-orange-500 text-white rounded-full flex items-center justify-center text-sm">
                  3
                </span>
                选择日期
              </h2>
              <div className="grid grid-cols-4 md:grid-cols-7 gap-2">
                {getWeekDates().map((date, i) => {
                  const dateStr = date.toISOString().split('T')[0];
                  return (
                    <button
                      key={i}
                      onClick={() => setSelectedDate(dateStr)}
                      className={`p-3 rounded-xl text-center border-2 transition-all ${
                        selectedDate === dateStr
                          ? 'border-orange-500 bg-orange-50'
                          : 'border-gray-200 hover:border-gray-300'
                      }`}
                    >
                      <div className="text-xs text-gray-500">
                        {date.toLocaleDateString('zh-CN', { weekday: 'short' })}
                      </div>
                      <div className="text-lg font-bold text-gray-900">{date.getDate()}</div>
                      <div className="text-xs text-gray-400">
                        {date.toLocaleDateString('zh-CN', { month: 'short' })}
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* 确认预约 */}
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
              <h2 className="text-lg font-semibold text-gray-900 mb-4">确认预约</h2>
              <div className="bg-gray-50 rounded-xl p-4 mb-4">
                {selectedSchedule && selectedPlayer && selectedDate ? (
                  <div className="space-y-2 text-sm">
                    <div className="flex justify-between">
                      <span className="text-gray-500">学员：</span>
                      <span className="font-medium">{selectedPlayer.name}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-500">课程：</span>
                      <span className="font-medium">{selectedSchedule.title}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-500">时间：</span>
                      <span className="font-medium">
                        {dayNames[selectedSchedule.dayOfWeek]} {selectedSchedule.startTime}-
                        {selectedSchedule.endTime}
                      </span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-500">地点：</span>
                      <span className="font-medium">{selectedSchedule.location}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-gray-500">日期：</span>
                      <span className="font-medium">
                        {new Date(selectedDate).toLocaleDateString('zh-CN')}
                      </span>
                    </div>
                  </div>
                ) : (
                  <div className="text-center text-gray-500 py-4">请完成以上选择</div>
                )}
              </div>
              <button
                onClick={handleBook}
                disabled={!selectedSchedule || !selectedPlayer || !selectedDate || submitting}
                className="w-full py-4 bg-orange-500 text-white rounded-xl font-semibold hover:bg-orange-600 disabled:opacity-50 flex items-center justify-center gap-2"
              >
                {submitting ? (
                  <>
                    <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
                    预约中...
                  </>
                ) : (
                  <>
                    <Check className="w-5 h-5" />
                    确认预约
                  </>
                )}
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  CheckCircle,
  XCircle,
  Clock,
  Users,
  Calendar,
  Save,
  RefreshCw,
} from 'lucide-react';

// 类型定义
type Plan = {
  id: string;
  title: string;
  date: string;
  group: string;
  theme?: string;
  duration: number;
  status?: string;
};

type Player = {
  id: string;
  name: string;
  group: string;
  parentPhone: string;
};

type CheckinRecord = {
  playerId: string;
  player: Player;
  attendance: string;
  signInTime?: string;
};

const attendanceOptions = [
  {
    value: 'present',
    label: '出勤',
    icon: CheckCircle,
    color: 'bg-green-500',
    textColor: 'text-green-600',
  },
  {
    value: 'absent',
    label: '缺勤',
    icon: XCircle,
    color: 'bg-red-500',
    textColor: 'text-red-600',
  },
  {
    value: 'late',
    label: '迟到',
    icon: Clock,
    color: 'bg-yellow-500',
    textColor: 'text-yellow-600',
  },
];

export default function CheckinPage() {
  const [plans, setPlans] = useState<Plan[]>([]);
  const [players, setPlayers] = useState<Player[]>([]);
  const [records, setRecords] = useState<Record<string, CheckinRecord>>({});
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // 临时记录（未保存的更改）
  const [tempRecords, setTempRecords] = useState<Record<string, string>>({});

  useEffect(() => {
    fetchPlans();
    fetchPlayers();
  }, []);

  async function fetchPlans() {
    try {
      const response = await fetchWithAuth('/api/plans?limit=20');
      const data = await response.json();
      if (data.success) {
        // 只显示已发布的
        setPlans(data.plans.filter((p: Plan) => !p.status || p.status === 'published'));
      }
    } catch (error) {
      console.error('获取教案失败:', error);
    } finally {
      setLoading(false);
    }
  }

  async function fetchPlayers() {
    try {
      const response = await fetchWithAuth('/api/players?status=training');
      const data = await response.json();
      if (data.success) {
        setPlayers(data.players);
      }
    } catch (error) {
      console.error('获取学员失败:', error);
    }
  }

  async function selectPlan(plan: Plan) {
    setSelectedPlan(plan);
    setTempRecords({});

    // 获取已有的签到记录
    try {
      const response = await fetchWithAuth(`/api/checkin?planId=${plan.id}`);
      const data = await response.json();
      if (data.success && data.records) {
        const recordMap: Record<string, CheckinRecord> = {};
        data.records.forEach((r: CheckinRecord) => {
          recordMap[r.playerId] = r;
        });
        setRecords(recordMap);
        // 初始化临时记录
        const temp: Record<string, string> = {};
        data.records.forEach((r: CheckinRecord) => {
          temp[r.playerId] = r.attendance;
        });
        setTempRecords(temp);
      } else {
        setRecords({});
        // 全部设为出勤
        const temp: Record<string, string> = {};
        players.forEach((p) => {
          temp[p.id] = 'present';
        });
        setTempRecords(temp);
      }
    } catch (error) {
      console.error('获取签到记录失败:', error);
    }
  }

  function handleAttendance(playerId: string, attendance: string) {
    setTempRecords((prev) => ({
      ...prev,
      [playerId]: attendance,
    }));
  }

  async function handleSave() {
    if (!selectedPlan) return;

    setSaving(true);
    try {
      const recordsList = players.map((player) => ({
        playerId: player.id,
        attendance: tempRecords[player.id] || 'present',
      }));

      const response = await fetchWithAuth('/api/checkin', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          planId: selectedPlan.id,
          records: recordsList,
        }),
      });

      const data = await response.json();
      if (data.success) {
        alert('签到保存成功！');
        selectPlan(selectedPlan); // 刷新
      } else {
        alert('保存失败');
      }
    } catch (error) {
      console.error('保存失败:', error);
      alert('保存失败');
    } finally {
      setSaving(false);
    }
  }

  function markAllPresent() {
    const temp: Record<string, string> = {};
    players.forEach((p) => {
      temp[p.id] = 'present';
    });
    setTempRecords(temp);
  }

  function getAttendanceCount(type: string) {
    return Object.values(tempRecords).filter((v) => v === type).length;
  }

  // 按班级分组学员
  const groupedPlayers = players.reduce(
    (acc, player) => {
      if (!acc[player.group]) acc[player.group] = [];
      acc[player.group].push(player);
      return acc;
    },
    {} as Record<string, Player[]>
  );

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/" className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </Link>
              <div>
                <h1 className="text-xl font-bold text-gray-900">签到点名</h1>
                <p className="text-sm text-gray-500">
                  {selectedPlan ? `已选: ${selectedPlan.title}` : '请选择训练课程'}
                </p>
              </div>
            </div>
            {selectedPlan && (
              <div className="flex items-center gap-2">
                <button
                  onClick={markAllPresent}
                  className="flex items-center gap-2 px-3 py-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                >
                  <RefreshCw className="w-4 h-4" />
                  全部出勤
                </button>
                <button
                  onClick={handleSave}
                  disabled={saving}
                  className="flex items-center gap-2 px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg disabled:opacity-50"
                >
                  {saving ? (
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <Save className="w-4 h-4" />
                  )}
                  保存签到
                </button>
              </div>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-6">
        {/* 统计卡片 */}
        {selectedPlan && (
          <div className="grid grid-cols-3 gap-4 mb-6">
            {attendanceOptions.map((option) => {
              const count = getAttendanceCount(option.value);
              const Icon = option.icon;
              return (
                <div
                  key={option.value}
                  className="bg-white rounded-xl p-4 shadow-sm border border-gray-100"
                >
                  <div className="flex items-center gap-3">
                    <div
                      className={`w-10 h-10 rounded-full ${option.color} flex items-center justify-center`}
                    >
                      <Icon className="w-5 h-5 text-white" />
                    </div>
                    <div>
                      <div className="text-2xl font-bold text-gray-900">{count}</div>
                      <div className="text-sm text-gray-500">{option.label}</div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* 课程选择 */}
        {!selectedPlan ? (
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <h2 className="font-semibold text-gray-900 mb-4">选择训练课程</h2>
            {plans.length === 0 ? (
              <div className="text-center py-8 text-gray-500">
                <Calendar className="w-12 h-12 mx-auto mb-3 text-gray-300" />
                <p>暂无训练课程</p>
                <Link
                  href="/plan/new"
                  className="text-orange-500 hover:text-orange-600 mt-2 inline-block"
                >
                  创建教案
                </Link>
              </div>
            ) : (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                {plans.map((plan) => (
                  <button
                    key={plan.id}
                    onClick={() => selectPlan(plan)}
                    className="p-4 text-left rounded-xl border-2 border-gray-200 hover:border-orange-500 transition-colors"
                  >
                    <div className="font-medium text-gray-900">{plan.title}</div>
                    <div className="text-sm text-gray-500 mt-1">
                      {new Date(plan.date).toLocaleDateString('zh-CN')}
                    </div>
                    <div className="flex items-center gap-2 mt-2">
                      <span className="text-xs px-2 py-0.5 bg-orange-100 text-orange-700 rounded">
                        {plan.group}
                      </span>
                      {plan.theme && <span className="text-xs text-gray-500">{plan.theme}</span>}
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>
        ) : (
          /* 学员签到列表 */
          <div className="space-y-6">
            <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
              <div className="flex items-center justify-between mb-4">
                <div>
                  <h2 className="font-semibold text-gray-900">{selectedPlan.title}</h2>
                  <p className="text-sm text-gray-500">
                    {new Date(selectedPlan.date).toLocaleDateString('zh-CN', {
                      weekday: 'long',
                      month: 'long',
                      day: 'numeric',
                    })}{' '}
                    · {selectedPlan.duration}分钟
                  </p>
                </div>
                <button
                  onClick={() => setSelectedPlan(null)}
                  className="text-sm text-orange-500 hover:text-orange-600"
                >
                  重新选择课程
                </button>
              </div>

              {players.length === 0 ? (
                <div className="text-center py-8 text-gray-500">
                  <Users className="w-12 h-12 mx-auto mb-3 text-gray-300" />
                  <p>暂无学员</p>
                  <Link
                    href="/players"
                    className="text-orange-500 hover:text-orange-600 mt-2 inline-block"
                  >
                    去添加学员
                  </Link>
                </div>
              ) : (
                Object.entries(groupedPlayers).map(([group, groupPlayers]) => (
                  <div key={group} className="mb-6">
                    <h3 className="text-sm font-medium text-gray-500 mb-3 flex items-center gap-2">
                      <Users className="w-4 h-4" />
                      {group} ({groupPlayers.length}人)
                    </h3>
                    <div className="grid gap-3">
                      {groupPlayers.map((player) => {
                        const currentAttendance = tempRecords[player.id] || 'present';
                        const existingRecord = records[player.id];

                        return (
                          <div
                            key={player.id}
                            className="flex items-center justify-between p-4 bg-gray-50 rounded-xl"
                          >
                            <div className="flex items-center gap-3">
                              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-orange-400 to-yellow-400 flex items-center justify-center text-white font-bold">
                                {player.name.charAt(0)}
                              </div>
                              <div>
                                <div className="font-medium text-gray-900">{player.name}</div>
                                {player.parentPhone && (
                                  <div className="text-xs text-gray-500">{player.parentPhone}</div>
                                )}
                              </div>
                            </div>

                            {/* 出勤状态 */}
                            <div className="flex items-center gap-2">
                              {attendanceOptions.map((option) => {
                                const Icon = option.icon;
                                const isSelected = currentAttendance === option.value;
                                return (
                                  <button
                                    key={option.value}
                                    onClick={() => handleAttendance(player.id, option.value)}
                                    className={`flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium transition-all ${
                                      isSelected
                                        ? `${option.color} text-white`
                                        : 'bg-white border border-gray-200 text-gray-600 hover:border-gray-300'
                                    }`}
                                  >
                                    <Icon className="w-4 h-4" />
                                    {option.label}
                                  </button>
                                );
                              })}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import {
  ArrowLeft,
  Plus,
  Search,
  User,
  Mail,
  Phone,
  Building2,
  Shield,
  X,
  AlertTriangle,
  Eye,
  EyeOff,
  Calendar,
  Trash2,
  Edit3,
  KeyRound,
} from 'lucide-react';
import { useAuth } from '@/components/AuthProvider';
import { fetchWithAuth } from '@/lib/auth';

// 教练类型
interface Coach {
  id: string;
  name: string;
  phone: string;
  email: string | null;
  role: string | null;
  avatar: string | null;
  campusId: string | null;
  specialties: string;
  status: string;
  hireDate: string | null;
  notes: string | null;
  createdAt: string;
  campus: { id: string; name: string } | null;
}

// 表单数据类型
interface CoachFormData {
  name: string;
  phone: string;
  email: string;
  password: string;
  role: string;
  status: string;
  campusId: string;
  specialties: string;
  notes: string;
}

const emptyForm: CoachFormData = {
  name: '',
  phone: '',
  email: '',
  password: '',
  role: 'coach',
  status: 'active',
  campusId: '',
  specialties: '',
  notes: '',
};

export default function CoachesPage() {
  const { user, isLoading, token } = useAuth();
  const router = useRouter();

  const [coaches, setCoaches] = useState<Coach[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');

  // 弹窗状态
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showResetPwdModal, setShowResetPwdModal] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  // 当前操作目标
  const [editingCoach, setEditingCoach] = useState<Coach | null>(null);
  const [formData, setFormData] = useState<CoachFormData>(emptyForm);
  const [resetPwdTarget, setResetPwdTarget] = useState<Coach | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<Coach | null>(null);
  const [newPassword, setNewPassword] = useState('');
  const [showNewPwd, setShowNewPwd] = useState(false);

  // 操作状态
  const [submitLoading, setSubmitLoading] = useState(false);
  const [submitMsg, setSubmitMsg] = useState<{ type: 'success' | 'error'; text: string } | null>(
    null
  );

  // 校区列表
  const [campuses, setCampuses] = useState<{ id: string; name: string }[]>([]);

  // 权限检查
  useEffect(() => {
    if (!isLoading && (!user || user.role !== 'admin')) {
      router.push('/');
    }
  }, [user, isLoading, router]);

  // 加载教练列表
  const fetchCoaches = useCallback(async () => {
    try {
      const res = await fetchWithAuth('/api/coaches');
      const data = await res.json();
      if (data.success) {
        setCoaches(data.data);
      }
    } catch (error) {
      console.error('获取教练列表失败:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  // 加载校区列表
  useEffect(() => {
    async function fetchCampuses() {
      try {
        const res = await fetchWithAuth('/api/campuses');
        const data = await res.json();
        if (data.success) {
          setCampuses(data.campuses || []);
        }
      } catch {
        // ignore
      }
    }
    fetchCampuses();
  }, []);

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchCoaches();
    }
  }, [user, fetchCoaches]);

  // 表单操作
  function handleFormChange(
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>
  ) {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  }

  function openCreateModal() {
    setFormData(emptyForm);
    setSubmitMsg(null);
    setShowCreateModal(true);
  }

  function openEditModal(coach: Coach) {
    setEditingCoach(coach);
    setFormData({
      name: coach.name,
      phone: coach.phone,
      email: coach.email || '',
      password: '',
      role: coach.role || 'coach',
      status: coach.status || 'active',
      campusId: coach.campusId || '',
      specialties: coach.specialties || '',
      notes: coach.notes || '',
    });
    setSubmitMsg(null);
    setShowEditModal(true);
  }

  function openResetPwdModal(coach: Coach) {
    setResetPwdTarget(coach);
    setNewPassword('');
    setShowNewPwd(false);
    setSubmitMsg(null);
    setShowResetPwdModal(true);
  }

  function openDeleteConfirm(coach: Coach) {
    setDeleteTarget(coach);
    setShowDeleteConfirm(true);
  }

  // 提交创建
  async function handleCreate() {
    if (!formData.name.trim() || !formData.phone.trim()) {
      setSubmitMsg({ type: 'error', text: '姓名和手机号是必填项' });
      return;
    }
    if (formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      setSubmitMsg({ type: 'error', text: '请输入有效的邮箱地址' });
      return;
    }
    if (formData.password && formData.password.length < 6) {
      setSubmitMsg({ type: 'error', text: '密码至少需要6个字符' });
      return;
    }

    setSubmitLoading(true);
    setSubmitMsg(null);
    try {
      const res = await fetchWithAuth('/api/coaches', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...formData,
          campusId: formData.campusId || undefined,
          email: formData.email || undefined,
          password: formData.password || undefined,
        }),
      });
      const data = await res.json();

      if (!data.success) {
        setSubmitMsg({ type: 'error', text: data.message || '创建失败' });
        return;
      }

      setShowCreateModal(false);
      fetchCoaches();
    } catch {
      setSubmitMsg({ type: 'error', text: '网络错误' });
    } finally {
      setSubmitLoading(false);
    }
  }

  // 提交编辑
  async function handleEdit() {
    if (!editingCoach) return;
    if (!formData.name.trim() || !formData.phone.trim()) {
      setSubmitMsg({ type: 'error', text: '姓名和手机号是必填项' });
      return;
    }

    setSubmitLoading(true);
    setSubmitMsg(null);
    try {
      const res = await fetchWithAuth(`/api/coaches/${editingCoach.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formData.name,
          phone: formData.phone,
          email: formData.email || null,
          role: formData.role,
          campusId: formData.campusId || null,
          specialties: formData.specialties,
          notes: formData.notes,
          status: formData.status || editingCoach.status,
        }),
      });
      const data = await res.json();

      if (!data.success) {
        setSubmitMsg({ type: 'error', text: data.message || '更新失败' });
        return;
      }

      setShowEditModal(false);
      fetchCoaches();
    } catch {
      setSubmitMsg({ type: 'error', text: '网络错误' });
    } finally {
      setSubmitLoading(false);
    }
  }

  // 重置密码
  async function handleResetPassword() {
    if (!resetPwdTarget) return;
    if (!newPassword || newPassword.length < 6) {
      setSubmitMsg({ type: 'error', text: '新密码至少需要6个字符' });
      return;
    }

    setSubmitLoading(true);
    setSubmitMsg(null);
    try {
      const res = await fetchWithAuth(`/api/coaches/${resetPwdTarget.id}/reset-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ newPassword }),
      });
      const data = await res.json();

      if (!data.success) {
        setSubmitMsg({ type: 'error', text: data.message || '重置失败' });
        return;
      }

      setShowResetPwdModal(false);
    } catch {
      setSubmitMsg({ type: 'error', text: '网络错误' });
    } finally {
      setSubmitLoading(false);
    }
  }

  // 删除教练
  async function handleDelete() {
    if (!deleteTarget) return;

    setSubmitLoading(true);
    try {
      const res = await fetchWithAuth(`/api/coaches/${deleteTarget.id}`, {
        method: 'DELETE',
      });
      const data = await res.json();

      if (!data.success) {
        setSubmitMsg({ type: 'error', text: data.message || '删除失败' });
        return;
      }

      setShowDeleteConfirm(false);
      setDeleteTarget(null);
      fetchCoaches();
    } catch {
      setSubmitMsg({ type: 'error', text: '网络错误' });
    } finally {
      setSubmitLoading(false);
    }
  }

