        await fetchWithAuth(`/api/goals/${editingGoal.id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            targetScore,
            targetDate: targetDate || null,
          }),
        });
      } else {
        // 创建
        await fetchWithAuth('/api/goals', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            playerId: selectedPlayerId,
            skillType,
            targetScore,
            targetDate: targetDate || null,
