// ==================== 雷达图组件 ====================
function RadarChart({
  abilities,
  size = 260,
  color = '#f97316',
  bgColor = 'rgba(249, 115, 22, 0.15)',
  showValues = true,
  showGridValues = true,
}: {
  abilities: AbilityDimensions;
  size?: number;
  color?: string;
  bgColor?: string;
  showValues?: boolean;
  showGridValues?: boolean;
}) {
  const labels = ['运球', '传球', '投篮', '防守', '体能', '战术'];
  const keys: (keyof AbilityDimensions)[] = [
    'dribbling',
    'passing',
    'shooting',
    'defending',
    'physical',
    'tactical',
  ];
  const values = keys.map((k) => abilities[k] || 5);

  const cx = size / 2;
  const cy = size / 2;
  const maxRadius = size / 2 - 28;

  const getPoint = (index: number, value: number) => {
    const angle = (Math.PI * 2 * index) / 6 - Math.PI / 2;
    const radius = (value / 10) * maxRadius;
    return {
      x: cx + radius * Math.cos(angle),
      y: cy + radius * Math.sin(angle),
    };
  };

  const gridLevels = [2, 4, 6, 8, 10];

  const dataPoints = values.map((v, i) => getPoint(i, v));
  const polygonPoints = dataPoints.map((p) => `${p.x},${p.y}`).join(' ');

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="mx-auto">
      {/* 网格线 */}
      {gridLevels.map((level) => {
        const points = keys
          .map((_, i) => {
            const p = getPoint(i, level);
            return `${p.x},${p.y}`;
          })
          .join(' ');
        return (
          <polygon
            key={level}
            points={points}
            fill="none"
            stroke={level === 10 ? '#d1d5db' : '#f3f4f6'}
            strokeWidth="1"
          />
        );
      })}

      {/* 轴线 */}
      {keys.map((_, i) => {
        const p = getPoint(i, 10);
        return <line key={i} x1={cx} y1={cy} x2={p.x} y2={p.y} stroke="#e5e7eb" strokeWidth="1" />;
      })}

      {/* 网格数值（仅第一轴） */}
      {showGridValues &&
        gridLevels.map((level) => {
          const p = getPoint(0, level);
          return (
            <text
              key={`grid-label-${level}`}
              x={p.x + 8}
              y={p.y + 4}
              className="text-[10px] fill-gray-400"
            >
              {level}
            </text>
          );
        })}

      {/* 数据区域 */}
      <polygon points={polygonPoints} fill={bgColor} stroke={color} strokeWidth="2.5" />

      {/* 数据点 */}
      {dataPoints.map((p, i) => (
        <circle key={i} cx={p.x} cy={p.y} r="5" fill={color} stroke="white" strokeWidth="2" />
      ))}

      {/* 标签 */}
      {labels.map((label, i) => {
        const p = getPoint(i, 11.2);
        return (
          <g key={`label-g-${i}`}>
            <text
              x={p.x}
              y={p.y - (showValues ? 7 : 0)}
              textAnchor="middle"
              dominantBaseline="middle"
              className="text-xs fill-gray-600 font-medium"
            >
              {label}
            </text>
            {showValues && (
              <text
                x={p.x}
                y={p.y + 10}
                textAnchor="middle"
                dominantBaseline="middle"
                className="text-[12px] fill-gray-900 font-bold"
              >
                {values[i]}
              </text>
            )}
          </g>
        );
      })}
    </svg>
  );
}

// ==================== 能力详情条 ====================
function AbilityBar({
  label,
  value,
  colorIndex,
  maxValue = 10,
}: {
  label: string;
  value: number;
  colorIndex: number;
  maxValue?: number;
}) {
  const gradients = [
    'from-blue-400 to-blue-500',
    'from-green-400 to-green-500',
    'from-orange-400 to-orange-500',
    'from-red-400 to-red-500',
    'from-purple-400 to-purple-500',
    'from-yellow-400 to-yellow-500',
  ];

  return (
    <div className="flex items-center gap-3">
      <span className="w-12 text-sm text-gray-600 font-medium shrink-0">{label}</span>
      <div className="flex-1 bg-gray-100 rounded-full h-2.5 overflow-hidden">
        <div
          className={`h-full bg-gradient-to-r ${gradients[colorIndex % gradients.length]} rounded-full transition-all duration-700`}
          style={{ width: `${(value / maxValue) * 100}%` }}
        />
      </div>
      <span className="w-8 text-sm font-bold text-gray-900 text-right">{value}</span>
    </div>
  );
}

