export default function GrowthReportDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const [report, setReport] = useState<GrowthReport | null>(null);
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);
  const [reportId, setReportId] = useState<string>('');
  const [abilityViewMode, setAbilityViewMode] = useState<'radar' | 'bars'>('radar');

  const [editForm, setEditForm] = useState({
    summary: '',
    strengths: [] as string[],
    improvements: [] as string[],
    goals: [] as string[],
    overallRating: 0,
  });

  useEffect(() => {
    params.then((p) => {
      setReportId(p.id);
      fetchReport(p.id);
    });
  }, [params]);

  async function fetchReport(id: string) {
    try {
      setLoading(true);
      const response = await fetchWithAuth(`/api/growth-reports/${id}`);
      const data = await response.json();

      if (data.success) {
        setReport(data.report);
        setEditForm({
          summary: data.report.summary || '',
          strengths: data.report.strengths || [],
          improvements: data.report.improvements || [],
          goals: data.report.goals || [],
          overallRating: data.report.overallRating || 0,
        });
      }
    } catch (error) {
      console.error('获取报告详情失败:', error);
    } finally {
      setLoading(false);
    }
  }

  async function handleSave() {
    if (!report) return;

    try {
      const response = await fetchWithAuth(`/api/growth-reports/${report.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          summary: editForm.summary,
          strengths: editForm.strengths,
          improvements: editForm.improvements,
          goals: editForm.goals,
          overallRating: editForm.overallRating,
          status: 'published',
        }),
      });

      const data = await response.json();
      if (data.success) {
        setIsEditing(false);
        fetchReport(reportId);
      }
    } catch (error) {
      console.error('保存失败:', error);
    }
  }

  async function handleDelete() {
    if (!report || !confirm('确定要删除这份报告吗？')) return;

    try {
      const response = await fetchWithAuth(`/api/growth-reports/${report.id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        router.push('/growth-reports');
      }
    } catch (error) {
      console.error('删除失败:', error);
    }
  }

  function handleExport() {
    window.print();
  }

  const abilityLabels: Record<string, string> = {
    dribbling: '运球',
    passing: '传球',
    shooting: '投篮',
    defending: '防守',
    physical: '体能',
    tactical: '战术',
  };

  // 计算能力均值和最强/最弱项
  const getAbilityAvg = () => {
    if (!report?.abilities) return 0;
    const vals = Object.values(report.abilities);
    return vals.reduce((a, b) => a + b, 0) / vals.length;
  };

  const getBestAbility = () => {
    if (!report?.abilities) return { key: '-', value: 0 };
    const entries = Object.entries(report.abilities) as [string, number][];
    entries.sort((a, b) => b[1] - a[1]);
    return { key: entries[0][0], value: entries[0][1] };
  };

  const getWeakestAbility = () => {
    if (!report?.abilities) return { key: '-', value: 0 };
    const entries = Object.entries(report.abilities) as [string, number][];
    entries.sort((a, b) => a[1] - b[1]);
    return { key: entries[0][0], value: entries[0][1] };
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  if (!report) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-lg font-semibold text-gray-900 mb-2">报告不存在</h2>
          <Link href="/growth-reports" className="text-orange-600 hover:text-orange-700">
            返回报告列表
          </Link>
        </div>
      </div>
    );
  }

  const bestAbility = getBestAbility();
  const weakestAbility = getWeakestAbility();
  const abilityAvg = getAbilityAvg();

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10 print:hidden">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/growth-reports" className="text-gray-400 hover:text-gray-600">
                <ArrowLeft className="w-5 h-5" />
              </Link>
              <div>
                <div className="flex items-center gap-2">
                  <span
                    className={`px-2 py-0.5 text-xs rounded-full font-medium ${
                      report.status === 'published'
                        ? 'bg-green-100 text-green-700'
                        : report.status === 'viewed'
                          ? 'bg-blue-100 text-blue-700'
                          : 'bg-gray-100 text-gray-700'
