                    <p className="text-sm text-gray-600 mb-2 line-clamp-2">{c.content}</p>

                    <div className="flex items-center gap-4 text-xs text-gray-400">
                      <span className="flex items-center gap-1">
                        <Clock className="w-3 h-3" />
