                                </span>
                              ))}
                            </div>
                          );
                        }
                      } catch {
                        /* ignore */
                      }
                      return null;
                    })()}
                  </div>

                  {/* 操作按钮 */}
                  <div className="flex items-center gap-1 ml-4 shrink-0">
                    <button
                      onClick={() => toggleFavorite(c)}
                      className="p-2 hover:bg-yellow-50 rounded-lg transition-colors"
                      title={c.isFavorite ? '取消收藏' : '收藏'}
                    >
                      <Star
                        className={`w-4 h-4 ${
                          c.isFavorite
                            ? 'fill-yellow-400 text-yellow-400'
