                      <Edit className="w-4 h-4 text-gray-400" />
                    </button>
                    <button
                      onClick={() => handleDelete(c.id)}
                      className="p-2 hover:bg-red-50 rounded-lg"
                      title="删除"
                    >
                      <Trash2 className="w-4 h-4 text-gray-400 hover:text-red-500" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* 新增/编辑模态框 */}
      {showForm && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-start justify-center pt-10 overflow-y-auto">
          <div className="bg-white rounded-2xl w-full max-w-2xl mx-4 mb-10">
            <div className="flex items-center justify-between p-6 border-b">
              <h2 className="text-lg font-bold">{editingCase ? '编辑案例' : '新增案例'}</h2>
              <button
                onClick={() => {
                  setShowForm(false);
                  resetForm();
                }}
                className="p-2 hover:bg-gray-100 rounded-lg"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              {/* 基本信息 */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">标题 *</label>
                  <input
                    type="text"
                    required
                    value={form.title}
                    onChange={(e) => setForm({ ...form, title: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500"
                    placeholder="案例标题"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">分类 *</label>
                  <select
                    value={form.category}
                    onChange={(e) => setForm({ ...form, category: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    {Object.entries(CATEGORIES).map(([key, label]) => (
                      <option key={key} value={key}>
                        {label}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">年龄组</label>
                  <select
                    value={form.ageGroup}
                    onChange={(e) => setForm({ ...form, ageGroup: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    {groups
                      .filter((g) => g !== 'all')
                      .map((g) => (
                        <option key={g} value={g}>
                          {g}
                        </option>
                      ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">技术类型</label>
                  <select
                    value={form.techType}
                    onChange={(e) => setForm({ ...form, techType: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    <option value="">不限</option>
                    {TECH_TYPES.map((t) => (
                      <option key={t} value={t}>
                        {t}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">水平</label>
                  <select
                    value={form.skillLevel}
                    onChange={(e) => setForm({ ...form, skillLevel: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    <option value="beginner">基础</option>
                    <option value="intermediate">进阶</option>
                    <option value="advanced">精英</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">时长(分钟)</label>
                  <input
                    type="number"
                    min={1}
                    max={120}
                    value={form.duration}
                    onChange={(e) => setForm({ ...form, duration: parseInt(e.target.value) || 10 })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">难度(1-5)</label>
                  <input
                    type="number"
                    min={1}
                    max={5}
                    value={form.difficulty}
                    onChange={(e) =>
                      setForm({ ...form, difficulty: parseInt(e.target.value) || 1 })
                    }
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">人数范围</label>
                  <div className="flex items-center gap-2">
                    <input
                      type="number"
                      min={1}
                      value={form.minPlayers}
                      onChange={(e) =>
                        setForm({ ...form, minPlayers: parseInt(e.target.value) || 1 })
                      }
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                    />
                    <span className="text-gray-400">-</span>
                    <input
                      type="number"
                      min={1}
                      value={form.maxPlayers}
                      onChange={(e) =>
                        setForm({ ...form, maxPlayers: parseInt(e.target.value) || 20 })
                      }
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                    />
                  </div>
                </div>
              </div>

              {/* 训练内容 */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">训练内容 *</label>
                <textarea
                  required
                  rows={3}
                  value={form.content}
                  onChange={(e) => setForm({ ...form, content: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500"
                  placeholder="描述训练活动的具体内容"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">训练方法</label>
                <textarea
                  rows={2}
                  value={form.method}
                  onChange={(e) => setForm({ ...form, method: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="组织方式和教学方法"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">要点目的</label>
                <textarea
                  rows={2}
                  value={form.keyPoints}
                  onChange={(e) => setForm({ ...form, keyPoints: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="关键要点和训练目的"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">教练引导语</label>
                <textarea
                  rows={2}
                  value={form.coachGuide}
                  onChange={(e) => setForm({ ...form, coachGuide: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="给教练的提示和引导语"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  器材（逗号分隔）
                </label>
                <input
                  type="text"
                  value={form.equipment}
                  onChange={(e) => setForm({ ...form, equipment: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="如：篮球, 标志物, 雪糕筒"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  标签（逗号分隔）
                </label>
                <input
                  type="text"
                  value={form.tags}
                  onChange={(e) => setForm({ ...form, tags: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  placeholder="如：团队配合, 快攻, 突破"
                />
              </div>

              <div className="flex justify-end gap-3 pt-4 border-t">
                <button
                  type="button"
                  onClick={() => {
                    setShowForm(false);
                    resetForm();
                  }}
                  className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
                >
                  取消
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg"
                >
                  {editingCase ? '保存修改' : '创建案例'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* 导入模态框 */}
      {showImport && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center">
          <div className="bg-white rounded-2xl w-full max-w-md mx-4 p-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-bold">导入案例</h2>
              <button
                onClick={() => setShowImport(false)}
                className="p-2 hover:bg-gray-100 rounded-lg"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="space-y-4">
              <button
                onClick={handleRagImport}
                disabled={importing}
                className="w-full p-4 border-2 border-dashed border-orange-300 rounded-xl hover:border-orange-500 hover:bg-orange-50 transition-colors text-left"
              >
                <div className="flex items-center gap-3 mb-2">
                  <Database className="w-5 h-5 text-orange-500" />
                  <span className="font-medium text-gray-900">从内置数据库导入</span>
                </div>
                <p className="text-sm text-gray-500">
                  从系统内置的训练教案库（RAG数据）导入案例到案例库
                </p>
              </button>

              <div className="text-center text-sm text-gray-400">
                支持导入已验证的训练案例，后续可手动编辑和管理
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { fetchWithAuth } from '@/lib/auth';
import {
  Calendar,
  MapPin,
  Users,
  Plus,
  Trash2,
  Edit3,
  Save,
  X,
  ArrowLeft,
  Target,
} from 'lucide-react';

type QuarterScore = {
  quarter: string;
  homeScore: number;
  opponentScore: number;
};

type PlayerStat = {
  playerId: string;
  playerName: string;
  points: number;
  rebounds: number;
  assists: number;
  steals: number;
  blocks: number;
  fouls: number;
  turnovers: number;
  minutes?: number;
};

type Match = {
  id: string;
  title: string;
  matchType: string;
  group: string;
  matchDate: string;
  location: string;
  teamName?: string;
  homeScore: number;
  opponent: string;
  opponentScore: number;
  quarterScores: QuarterScore[];
  result: string;
  isHome: boolean;
  status: string;
  players: string[];
  playerStats: PlayerStat[];
  coachName?: string;
  notes?: string;
  events: MatchEvent[];
};

type MatchEvent = {
  id: string;
  eventTime: string;
  quarter?: number;
  playerId?: string;
  playerName?: string;
  eventType: string;
  description?: string;
  points?: number;
  relatedPlayerId?: string;
  relatedPlayerName?: string;
};

type Player = {
  id: string;
  name: string;
  group: string;
};

export default function MatchDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const [match, setMatch] = useState<Match | null>(null);
  const [players, setPlayers] = useState<Player[]>([]);
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);
  const [showAddEvent, setShowAddEvent] = useState(false);
  const [matchId, setMatchId] = useState<string>('');

  // 编辑表单
  const [editForm, setEditForm] = useState({
    homeScore: 0,
    opponentScore: 0,
    quarterScores: [] as QuarterScore[],
    notes: '',
  });

  // 新增事件表单
  const [eventForm, setEventForm] = useState({
    eventTime: '',
    quarter: 1,
    playerId: '',
    playerName: '',
    eventType: 'score',
    description: '',
    points: 2,
  });

  useEffect(() => {
    params.then((p) => {
      setMatchId(p.id);
      fetchMatch(p.id);
    });
  }, [params]);

  const fetchPlayers = useCallback(async () => {
    try {
      const response = await fetchWithAuth('/api/players?limit=100');
      const data = await response.json();
      if (data.success) {
        setPlayers(data.players.filter((p: Player) => p.group === match?.group));
      }
    } catch (error) {
      console.error('获取球员列表失败:', error);
    }
  }, [match?.group]);

  useEffect(() => {
    fetchPlayers();
  }, [fetchPlayers]);

  async function fetchMatch(id: string) {
    try {
      setLoading(true);
      const response = await fetchWithAuth(`/api/matches/${id}`);
      const data = await response.json();

      if (data.success) {
        setMatch(data.match);
        setEditForm({
          homeScore: data.match.homeScore,
          opponentScore: data.match.opponentScore,
          quarterScores: data.match.quarterScores || [],
          notes: data.match.notes || '',
        });
      }
    } catch (error) {
      console.error('获取比赛详情失败:', error);
    } finally {
      setLoading(false);
    }
  }

  async function handleUpdateScore() {
    if (!match) return;

    try {
      const response = await fetchWithAuth(`/api/matches/${match.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          homeScore: editForm.homeScore,
          opponentScore: editForm.opponentScore,
          quarterScores: editForm.quarterScores,
          notes: editForm.notes,
        }),
      });

      const data = await response.json();
      if (data.success) {
        setIsEditing(false);
        fetchMatch(match.id);
      }
    } catch (error) {
      console.error('更新比分失败:', error);
    }
  }

  async function handleAddEvent() {
    if (!match) return;

    try {
      const selectedPlayer = players.find((p) => p.id === eventForm.playerId);

      const response = await fetchWithAuth('/api/match-events', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          matchId: match.id,
          ...eventForm,
          playerName: selectedPlayer?.name || eventForm.playerName,
        }),
      });

      const data = await response.json();
      if (data.success) {
        setShowAddEvent(false);
        setEventForm({
          eventTime: '',
          quarter: 1,
          playerId: '',
          playerName: '',
          eventType: 'score',
          description: '',
          points: 2,
        });
        fetchMatch(match.id);
      }
    } catch (error) {
      console.error('添加事件失败:', error);
    }
  }

  async function handleDeleteEvent(eventId: string) {
    try {
      await fetchWithAuth(`/api/match-events?id=${eventId}`, { method: 'DELETE' });
      fetchMatch(matchId);
    } catch (error) {
      console.error('删除事件失败:', error);
    }
  }

  async function handleDeleteMatch() {
    if (!match || !confirm('确定要删除这场比赛吗？')) return;

    try {
      const response = await fetchWithAuth(`/api/matches/${match.id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        router.push('/matches');
      }
    } catch (error) {
      console.error('删除比赛失败:', error);
    }
  }

  const eventTypeLabels: Record<string, string> = {
    score: '得分',
    rebound: '篮板',
    assist: '助攻',
    steal: '抢断',
    block: '盖帽',
    foul: '犯规',
    turnover: '失误',
    substitution: '换人',
  };

  const eventTypeColors: Record<string, string> = {
    score: 'bg-orange-100 text-orange-700',
    rebound: 'bg-blue-100 text-blue-700',
    assist: 'bg-green-100 text-green-700',
    steal: 'bg-yellow-100 text-yellow-700',
    block: 'bg-purple-100 text-purple-700',
    foul: 'bg-red-100 text-red-700',
    turnover: 'bg-gray-100 text-gray-700',
    substitution: 'bg-cyan-100 text-cyan-700',
  };

  const resultColors: Record<string, string> = {
    win: 'bg-green-500',
    lose: 'bg-red-500',
    draw: 'bg-gray-500',
    pending: 'bg-yellow-500',
  };

  const resultLabels: Record<string, string> = {
    win: '胜',
    lose: '负',
    draw: '平',
    pending: '待定',
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  if (!match) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-lg font-semibold text-gray-900 mb-2">比赛不存在</h2>
          <Link href="/matches" className="text-orange-600 hover:text-orange-700">
            返回比赛列表
          </Link>
        </div>
      </div>
    );
  }

  // 计算球员统计数据
  const playerStatsMap: Record<string, PlayerStat> = {};
  match.events.forEach((event) => {
    if (event.playerId) {
      if (!playerStatsMap[event.playerId]) {
        playerStatsMap[event.playerId] = {
          playerId: event.playerId,
          playerName: event.playerName || '未知',
          points: 0,
          rebounds: 0,
          assists: 0,
          steals: 0,
          blocks: 0,
          fouls: 0,
          turnovers: 0,
        };
      }
      switch (event.eventType) {
        case 'score':
          playerStatsMap[event.playerId].points += event.points || 0;
          break;
        case 'rebound':
          playerStatsMap[event.playerId].rebounds += 1;
          break;
        case 'assist':
          playerStatsMap[event.playerId].assists += 1;
          break;
        case 'steal':
          playerStatsMap[event.playerId].steals += 1;
          break;
        case 'block':
          playerStatsMap[event.playerId].blocks += 1;
          break;
        case 'foul':
          playerStatsMap[event.playerId].fouls += 1;
          break;
        case 'turnover':
          playerStatsMap[event.playerId].turnovers += 1;
          break;
      }
    }
  });

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/matches" className="text-gray-400 hover:text-gray-600">
                <ArrowLeft className="w-5 h-5" />
              </Link>
              <div>
                <div className="flex items-center gap-2">
                  <span
                    className={`px-2 py-0.5 text-xs text-white rounded ${resultColors[match.result]}`}
                  >
                    {resultLabels[match.result]}
                  </span>
                  <span className="px-2 py-0.5 bg-orange-100 text-orange-700 text-xs rounded">
                    {match.group}
                  </span>
                </div>
                <h1 className="text-lg font-bold text-gray-900 mt-1">{match.title}</h1>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button
                onClick={() => setShowAddEvent(true)}
                className="flex items-center gap-1 px-3 py-1.5 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors text-sm"
              >
                <Plus className="w-4 h-4" />
                记录事件
              </button>
              <button
                onClick={handleDeleteMatch}
                className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
              >
                <Trash2 className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-6">
        {/* 比分板 */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
          <div className="bg-gradient-to-r from-orange-500 to-orange-600 text-white p-6">
            <div className="flex items-center justify-between">
              <div className="text-center flex-1">
                <div className="text-sm opacity-80 mb-2">
                  {match.isHome ? '我方' : match.opponent}
                </div>
                {isEditing ? (
                  <input
                    type="number"
                    value={editForm.homeScore}
                    onChange={(e) =>
                      setEditForm({
                        ...editForm,
                        homeScore: parseInt(e.target.value) || 0,
                      })
                    }
                    className="w-20 text-5xl font-bold text-center bg-white/20 rounded-lg px-2 py-1 outline-none"
                  />
                ) : (
                  <div className="text-5xl font-bold">{match.homeScore}</div>
                )}
                <div className="text-sm mt-2">{match.isHome ? match.teamName || '我方' : ''}</div>
              </div>

              <div className="text-center px-8">
                <div className="text-2xl font-bold opacity-80">VS</div>
                <div className="text-sm opacity-60 mt-2">
                  {new Date(match.matchDate).toLocaleDateString('zh-CN')}
                </div>
              </div>

              <div className="text-center flex-1">
                <div className="text-sm opacity-80 mb-2">
                  {match.isHome ? match.opponent : '我方'}
                </div>
                {isEditing ? (
                  <input
                    type="number"
                    value={editForm.opponentScore}
                    onChange={(e) =>
                      setEditForm({
                        ...editForm,
                        opponentScore: parseInt(e.target.value) || 0,
                      })
                    }
                    className="w-20 text-5xl font-bold text-center bg-white/20 rounded-lg px-2 py-1 outline-none"
                  />
                ) : (
                  <div className="text-5xl font-bold">{match.opponentScore}</div>
                )}
                <div className="text-sm mt-2">{match.isHome ? '' : match.teamName || '我方'}</div>
              </div>
            </div>
          </div>

          <div className="p-4 flex items-center justify-between border-t border-gray-100">
            <div className="flex items-center gap-4 text-sm text-gray-500">
              <span className="flex items-center gap-1">
                <MapPin className="w-4 h-4" />
                {match.location || '未知地点'}
              </span>
              <span className="flex items-center gap-1">
                <Calendar className="w-4 h-4" />
                {new Date(match.matchDate).toLocaleString('zh-CN')}
              </span>
            </div>
            {isEditing ? (
              <div className="flex gap-2">
                <button
                  onClick={() => setIsEditing(false)}
                  className="px-3 py-1.5 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors text-sm"
                >
                  取消
                </button>
                <button
                  onClick={handleUpdateScore}
                  className="flex items-center gap-1 px-3 py-1.5 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors text-sm"
                >
                  <Save className="w-4 h-4" />
                  保存
                </button>
              </div>
            ) : (
              <button
                onClick={() => setIsEditing(true)}
                className="flex items-center gap-1 px-3 py-1.5 text-orange-600 hover:bg-orange-50 rounded-lg transition-colors text-sm"
              >
                <Edit3 className="w-4 h-4" />
                修改比分
              </button>
            )}
          </div>
        </div>

        {/* 球员数据统计 */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden mb-6">
          <div className="p-4 border-b border-gray-100">
            <h2 className="font-semibold text-gray-900 flex items-center gap-2">
              <Users className="w-5 h-5 text-orange-500" />
              球员数据
            </h2>
          </div>
          <div className="overflow-x-auto">
            {Object.keys(playerStatsMap).length > 0 ? (
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">
                      球员
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      得分
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      篮板
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      助攻
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      抢断
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      盖帽
                    </th>
                    <th className="px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">
                      犯规
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {Object.values(playerStatsMap).map((stats: PlayerStat) => (
                    <tr key={stats.playerId} className="hover:bg-gray-50">
                      <td className="px-4 py-3 text-sm font-medium text-gray-900">
                        {stats.playerName}
                      </td>
                      <td className="px-4 py-3 text-center text-sm font-bold text-orange-600">
                        {stats.points}
                      </td>
                      <td className="px-4 py-3 text-center text-sm">{stats.rebounds}</td>
                      <td className="px-4 py-3 text-center text-sm">{stats.assists}</td>
                      <td className="px-4 py-3 text-center text-sm">{stats.steals}</td>
                      <td className="px-4 py-3 text-center text-sm">{stats.blocks}</td>
                      <td className="px-4 py-3 text-center text-sm text-red-500">{stats.fouls}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div className="p-8 text-center text-gray-500">暂无球员统计数据</div>
            )}
          </div>
        </div>

        {/* 比赛事件时间线 */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-4 border-b border-gray-100">
            <h2 className="font-semibold text-gray-900 flex items-center gap-2">
              <Target className="w-5 h-5 text-orange-500" />
              比赛事件
            </h2>
          </div>
          <div className="p-4">
            {match.events.length > 0 ? (
              <div className="relative">
                {/* 时间线 */}
                <div className="absolute left-6 top-0 bottom-0 w-0.5 bg-gray-200"></div>

                <div className="space-y-4">
                  {match.events.map((event, index) => (
                    <div key={event.id} className="relative flex items-start gap-4 pl-12">
                      {/* 时间线节点 */}
                      <div
                        className={`absolute left-4 w-5 h-5 rounded-full border-2 border-white ${eventTypeColors[event.eventType]} z-10 flex items-center justify-center`}
                      >
                        {event.eventType === 'score' && (
                          <div className="w-2 h-2 bg-orange-500 rounded-full"></div>
                        )}
                        {event.eventType === 'rebound' && (
                          <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                        )}
                        {event.eventType === 'assist' && (
                          <div className="w-2 h-2 bg-green-500 rounded-full"></div>
                        )}
                        {event.eventType === 'steal' && (
                          <div className="w-2 h-2 bg-yellow-500 rounded-full"></div>
                        )}
                        {event.eventType === 'block' && (
                          <div className="w-2 h-2 bg-purple-500 rounded-full"></div>
                        )}
                        {event.eventType === 'foul' && (
                          <div className="w-2 h-2 bg-red-500 rounded-full"></div>
                        )}
                      </div>

                      {/* 事件内容 */}
                      <div className="flex-1 bg-gray-50 rounded-lg p-3">
                        <div className="flex items-center justify-between mb-1">
                          <div className="flex items-center gap-2">
                            <span
                              className={`px-2 py-0.5 text-xs rounded ${eventTypeColors[event.eventType]}`}
                            >
                              {eventTypeLabels[event.eventType]}
                            </span>
                            {event.quarter && (
                              <span className="text-xs text-gray-500">第{event.quarter}节</span>
                            )}
                            <span className="text-xs text-gray-400">{event.eventTime}</span>
                          </div>
                          <button
                            onClick={() => handleDeleteEvent(event.id)}
                            className="text-gray-400 hover:text-red-500"
                          >
                            <X className="w-4 h-4" />
                          </button>
                        </div>
                        <div className="text-sm">
                          <span className="font-medium text-gray-900">
                            {event.playerName || '未知球员'}
                          </span>
                          {event.eventType === 'score' && event.points && (
                            <span className="ml-2 text-orange-600 font-bold">
                              +{event.points}分
                            </span>
                          )}
                          {event.description && (
                            <span className="ml-2 text-gray-500">{event.description}</span>
                          )}
                        </div>
                        {event.relatedPlayerName && (
                          <div className="text-xs text-gray-500 mt-1">
                            对抗: {event.relatedPlayerName}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ) : (
              <div className="text-center py-8 text-gray-500">暂无比赛事件记录</div>
            )}
          </div>
        </div>
      </main>

      {/* 添加事件弹窗 */}
      {showAddEvent && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-md">
            <div className="p-6 border-b border-gray-200">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-bold text-gray-900">记录比赛事件</h2>
                <button
                  onClick={() => setShowAddEvent(false)}
                  className="text-gray-400 hover:text-gray-600"
                >
                  ✕
                </button>
              </div>
            </div>

            <div className="p-6 space-y-4">
              <div className="grid grid-cols-3 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">节次</label>
                  <select
                    value={eventForm.quarter}
                    onChange={(e) =>
                      setEventForm({
                        ...eventForm,
                        quarter: parseInt(e.target.value),
                      })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  >
                    <option value={1}>第1节</option>
                    <option value={2}>第2节</option>
                    <option value={3}>第3节</option>
                    <option value={4}>第4节</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">时间</label>
                  <input
                    type="text"
                    value={eventForm.eventTime}
                    onChange={(e) => setEventForm({ ...eventForm, eventTime: e.target.value })}
                    placeholder="12:34"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">球员</label>
                  <select
                    value={eventForm.playerId}
                    onChange={(e) => setEventForm({ ...eventForm, playerId: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  >
                    <option value="">选择球员</option>
                    {players.map((player) => (
                      <option key={player.id} value={player.id}>
                        {player.name}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">事件类型</label>
                <select
                  value={eventForm.eventType}
                  onChange={(e) => setEventForm({ ...eventForm, eventType: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                >
                  <option value="score">得分</option>
                  <option value="rebound">篮板</option>
                  <option value="assist">助攻</option>
                  <option value="steal">抢断</option>
                  <option value="block">盖帽</option>
                  <option value="foul">犯规</option>
                  <option value="turnover">失误</option>
                  <option value="substitution">换人</option>
                </select>
              </div>

              {eventForm.eventType === 'score' && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">得分</label>
                  <select
                    value={eventForm.points}
                    onChange={(e) =>
                      setEventForm({
                        ...eventForm,
                        points: parseInt(e.target.value),
                      })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  >
                    <option value={1}>1分（罚球）</option>
                    <option value={2}>2分</option>
                    <option value={3}>3分</option>
                  </select>
                </div>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">描述</label>
                <input
                  type="text"
                  value={eventForm.description}
                  onChange={(e) => setEventForm({ ...eventForm, description: e.target.value })}
                  placeholder="事件描述（可选）"
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                />
              </div>
            </div>

            <div className="p-6 border-t border-gray-200">
              <div className="flex gap-3">
                <button
                  onClick={() => setShowAddEvent(false)}
                  className="flex-1 px-4 py-2 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  取消
                </button>
                <button
                  onClick={handleAddEvent}
                  disabled={!eventForm.playerId && !eventForm.playerName}
                  className="flex-1 px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  添加
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { fetchWithAuth } from '@/lib/auth';
import {
  Trophy,
  Plus,
  Calendar,
  MapPin,
  Users,
  ChevronRight,
  Search,
  Filter,
  Medal,
  Target,
  TrendingUp,
  Clock,
} from 'lucide-react';

type Match = {
  id: string;
  title: string;
  matchType: string;
  group: string;
  matchDate: string;
  location: string;
  teamName?: string;
  homeScore: number;
  opponent: string;
  opponentScore: number;
  result: string;
  isHome: boolean;
  status: string;
  _count?: { events: number };
};

export default function MatchesPage() {
  const router = useRouter();
  const [matches, setMatches] = useState<Match[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('');
  const [selectedResult, setSelectedResult] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);

  // 创建表单状态
  const [createForm, setCreateForm] = useState({
    title: '',
    matchType: 'league',
    group: 'U10',
    matchDate: '',
    location: '',
    opponent: '',
    teamName: '',
    isHome: true,
  });

  const fetchMatches = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedGroup) params.set('group', selectedGroup);
      if (selectedResult) params.set('result', selectedResult);

      const response = await fetch(`/api/matches?${params.toString()}`);
      const data = await response.json();

      if (data.success) {
        setMatches(data.matches);
      }
    } catch (error) {
      console.error('获取比赛列表失败:', error);
    } finally {
      setLoading(false);
    }
  }, [selectedGroup, selectedResult]);

  useEffect(() => {
    fetchMatches();
  }, [fetchMatches]);

  async function handleCreateMatch() {
    try {
      const response = await fetchWithAuth('/api/matches', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...createForm,
          matchDate: new Date(createForm.matchDate).toISOString(),
        }),
      });

      const data = await response.json();

      if (data.success) {
        setShowCreateModal(false);
        setCreateForm({
          title: '',
          matchType: 'league',
          group: 'U10',
          matchDate: '',
          location: '',
          opponent: '',
          teamName: '',
          isHome: true,
        });
        fetchMatches();
        router.push(`/matches/${data.match.id}`);
      }
    } catch (error) {
      console.error('创建比赛失败:', error);
    }
  }

  const filteredMatches = matches.filter((match) => {
    if (!searchTerm) return true;
    const term = searchTerm.toLowerCase();
    return (
      match.title.toLowerCase().includes(term) ||
      match.opponent.toLowerCase().includes(term) ||
      match.teamName?.toLowerCase().includes(term) ||
      match.location.toLowerCase().includes(term)
    );
  });

  const stats = {
    total: matches.length,
    wins: matches.filter((m) => m.result === 'win').length,
    losses: matches.filter((m) => m.result === 'lose').length,
    draws: matches.filter((m) => m.result === 'draw').length,
  };

  const resultColors: Record<string, string> = {
    win: 'bg-green-100 text-green-700',
    lose: 'bg-red-100 text-red-700',
    draw: 'bg-gray-100 text-gray-700',
    pending: 'bg-yellow-100 text-yellow-700',
  };

  const resultLabels: Record<string, string> = {
    win: '胜',
    lose: '负',
    draw: '平',
    pending: '待定',
  };

  const matchTypeLabels: Record<string, string> = {
    league: '联赛',
    cup: '杯赛',
    friendly: '友谊赛',
    practice: '内部赛',
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/" className="text-gray-400 hover:text-gray-600">
                <ChevronRight className="w-5 h-5 rotate-180" />
              </Link>
              <div className="flex items-center gap-2">
                <Trophy className="w-6 h-6 text-orange-500" />
                <h1 className="text-xl font-bold text-gray-900">比赛记录</h1>
              </div>
            </div>
            <button
              onClick={() => setShowCreateModal(true)}
              className="flex items-center gap-2 px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors"
            >
              <Plus className="w-4 h-4" />
              记录比赛
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* 统计卡片 */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                <Target className="w-5 h-5 text-blue-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-gray-900">{stats.total}</div>
                <div className="text-sm text-gray-500">总比赛</div>
              </div>
            </div>
          </div>
          <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
                <Medal className="w-5 h-5 text-green-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-green-600">{stats.wins}</div>
                <div className="text-sm text-gray-500">获胜</div>
              </div>
            </div>
          </div>
          <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-red-100 rounded-lg flex items-center justify-center">
                <TrendingUp className="w-5 h-5 text-red-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-red-600">{stats.losses}</div>
                <div className="text-sm text-gray-500">失利</div>
              </div>
            </div>
          </div>
          <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gray-100 rounded-lg flex items-center justify-center">
                <Users className="w-5 h-5 text-gray-600" />
              </div>
              <div>
                <div className="text-2xl font-bold text-gray-600">{stats.draws}</div>
                <div className="text-sm text-gray-500">平局</div>
              </div>
            </div>
          </div>
        </div>

        {/* 筛选栏 */}
        <div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100 mb-6">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="w-5 h-5 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
              <input
                type="text"
                placeholder="搜索比赛、对手..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent"
              />
            </div>
            <div className="flex gap-2">
              <select
                value={selectedGroup}
                onChange={(e) => setSelectedGroup(e.target.value)}
                className="px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
              >
                <option value="">全部分组</option>
                <option value="U6">U6</option>
                <option value="U8">U8</option>
                <option value="U10">U10</option>
                <option value="U12">U12</option>
                <option value="U14">U14</option>
              </select>
              <select
                value={selectedResult}
                onChange={(e) => setSelectedResult(e.target.value)}
                className="px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
              >
                <option value="">全部结果</option>
                <option value="win">胜</option>
                <option value="lose">负</option>
                <option value="draw">平</option>
              </select>
            </div>
          </div>
        </div>

        {/* 比赛列表 */}
        {loading ? (
          <div className="flex items-center justify-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"></div>
          </div>
        ) : filteredMatches.length === 0 ? (
          <div className="bg-white rounded-xl p-12 shadow-sm border border-gray-100 text-center">
            <Trophy className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">暂无比赛记录</h3>
            <p className="text-gray-500 mb-4">开始记录第一场比赛吧</p>
            <button
              onClick={() => setShowCreateModal(true)}
              className="text-orange-600 hover:text-orange-700"
            >
              记录比赛 →
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredMatches.map((match) => (
              <Link
                key={match.id}
                href={`/matches/${match.id}`}
                className="bg-white rounded-xl p-5 shadow-sm hover:shadow-md transition-shadow border border-gray-100"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <span
                      className={`px-2 py-1 text-xs rounded-full ${resultColors[match.result]}`}
                    >
                      {resultLabels[match.result]}
                    </span>
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">
                      {matchTypeLabels[match.matchType] || match.matchType}
                    </span>
                  </div>
                  <span className="px-2 py-1 bg-orange-100 text-orange-700 text-xs rounded-full">
                    {match.group}
                  </span>
                </div>

                <h3 className="font-semibold text-gray-900 mb-3 line-clamp-2">{match.title}</h3>

                {/* 比分 */}
                <div className="flex items-center justify-center gap-4 py-3 bg-gray-50 rounded-lg mb-3">
                  <div className="text-center">
                    <div className="text-xs text-gray-500 mb-1">
                      {match.isHome ? '我方' : match.opponent}
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                      {match.isHome ? match.homeScore : match.opponentScore}
                    </div>
                  </div>
                  <div className="text-gray-300 text-lg">-</div>
                  <div className="text-center">
                    <div className="text-xs text-gray-500 mb-1">
                      {match.isHome ? match.opponent : '我方'}
                    </div>
                    <div className="text-2xl font-bold text-gray-900">
                      {match.isHome ? match.opponentScore : match.homeScore}
                    </div>
                  </div>
                </div>

                <div className="flex items-center gap-4 text-xs text-gray-400">
                  <span className="flex items-center gap-1">
                    <Calendar className="w-3 h-3" />
                    {new Date(match.matchDate).toLocaleDateString('zh-CN')}
                  </span>
                  <span className="flex items-center gap-1">
                    <MapPin className="w-3 h-3" />
                    {match.location || '未知地点'}
                  </span>
                </div>
              </Link>
            ))}
          </div>
        )}
      </main>

      {/* 创建比赛弹窗 */}
      {showCreateModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-gray-200 sticky top-0 bg-white">
              <div className="flex items-center justify-between">
                <h2 className="text-lg font-bold text-gray-900">记录比赛</h2>
                <button
                  onClick={() => setShowCreateModal(false)}
                  className="text-gray-400 hover:text-gray-600"
                >
                  ✕
                </button>
              </div>
            </div>

            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">比赛标题 *</label>
                <input
                  type="text"
                  value={createForm.title}
                  onChange={(e) => setCreateForm({ ...createForm, title: e.target.value })}
                  placeholder="如: 2024年春季联赛第三轮"
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">比赛类型</label>
                  <select
                    value={createForm.matchType}
                    onChange={(e) =>
                      setCreateForm({
                        ...createForm,
                        matchType: e.target.value,
                      })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  >
                    <option value="league">联赛</option>
                    <option value="cup">杯赛</option>
                    <option value="friendly">友谊赛</option>
                    <option value="practice">内部赛</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">分组</label>
                  <select
                    value={createForm.group}
                    onChange={(e) => setCreateForm({ ...createForm, group: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  >
                    <option value="U6">U6</option>
                    <option value="U8">U8</option>
                    <option value="U10">U10</option>
                    <option value="U12">U12</option>
                    <option value="U14">U14</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">比赛日期 *</label>
                  <input
                    type="datetime-local"
                    value={createForm.matchDate}
                    onChange={(e) =>
                      setCreateForm({
                        ...createForm,
                        matchDate: e.target.value,
                      })
                    }
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">比赛地点</label>
                  <input
                    type="text"
                    value={createForm.location}
                    onChange={(e) => setCreateForm({ ...createForm, location: e.target.value })}
                    placeholder="如: 篮球馆"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">对手名称 *</label>
                <input
                  type="text"
                  value={createForm.opponent}
                  onChange={(e) => setCreateForm({ ...createForm, opponent: e.target.value })}
                  placeholder="如: 阳光队"
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">我方球队名称</label>
                <input
                  type="text"
                  value={createForm.teamName}
                  onChange={(e) => setCreateForm({ ...createForm, teamName: e.target.value })}
                  placeholder="如: 雄鹰队"
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500"
                />
              </div>

              <div>
                <label className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    checked={createForm.isHome}
                    onChange={(e) => setCreateForm({ ...createForm, isHome: e.target.checked })}
                    className="w-4 h-4 text-orange-500 rounded focus:ring-orange-500"
                  />
                  <span className="text-sm text-gray-700">主场比赛</span>
                </label>
              </div>
            </div>

            <div className="p-6 border-t border-gray-200 sticky bottom-0 bg-white">
              <div className="flex gap-3">
                <button
                  onClick={() => setShowCreateModal(false)}
                  className="flex-1 px-4 py-2 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  取消
                </button>
                <button
                  onClick={handleCreateMatch}
                  disabled={!createForm.title || !createForm.matchDate || !createForm.opponent}
                  className="flex-1 px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  创建比赛
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { fetchWithAuth } from '@/lib/auth';
import {
  Bell,
  Send,
  CheckCircle,
  Clock,
  AlertCircle,
  Trash2,
  Eye,
  Plus,
  Filter,
  RefreshCw,
  FileText,
  BarChart3,
  Users,
  Zap,
  Edit3,
  ToggleLeft,
  ToggleRight,
  Tag,
} from 'lucide-react';

// ========== 类型定义 ==========

interface Notification {
  id: string;
  title: string;
  content: string;
  type: string;
  status: string;
  channel: string;
  player?: { id: string; name: string };
  guardianName: string | null;
  template?: { id: string; code: string; name: string };
  sentAt: string | null;
  readAt: string | null;
  createdAt: string;
}

interface Player {
  id: string;
  name: string;
  parentPhone: string | null;
}

interface NotificationTemplate {
  id: string;
  code: string;
  name: string;
  category: string;
  title: string;
  content: string;
  variables: string;
  isActive: boolean;
  isAutomated: boolean;
  priority: string;
}

interface NotificationStats {
  total: number;
  pending: number;
  sent: number;
  read: number;
  failed: number;
  unreadRate: number;
  readRate: number;
  todaySent: number;
  weekSent: number;
  byType: Record<string, number>;
  byChannel: Record<string, number>;
}

type Tab = 'list' | 'templates' | 'stats';

// ========== 状态标签 ==========

const statusConfig: Record<string, { label: string; class: string }> = {
  pending: { label: '待发送', class: 'bg-yellow-100 text-yellow-800' },
  sent: { label: '已发送', class: 'bg-blue-100 text-blue-800' },
  read: { label: '已读', class: 'bg-green-100 text-green-800' },
  failed: { label: '失败', class: 'bg-red-100 text-red-800' },
};

const typeConfig: Record<string, { label: string; class: string }> = {
  system: { label: '系统', class: 'bg-gray-100 text-gray-700' },
  course: { label: '课程', class: 'bg-blue-100 text-blue-700' },
  reminder: { label: '提醒', class: 'bg-orange-100 text-orange-700' },
  marketing: { label: '营销', class: 'bg-purple-100 text-purple-700' },
};

const categoryConfig: Record<string, { label: string; class: string }> = {
  system: { label: '系统', class: 'bg-gray-100 text-gray-700' },
  course: { label: '课程', class: 'bg-blue-100 text-blue-700' },
  reminder: { label: '提醒', class: 'bg-orange-100 text-orange-700' },
  marketing: { label: '营销', class: 'bg-purple-100 text-purple-700' },
};

const priorityConfig: Record<string, { label: string; class: string }> = {
  low: { label: '低', class: 'bg-gray-100 text-gray-600' },
  normal: { label: '普通', class: 'bg-blue-100 text-blue-700' },
  high: { label: '高', class: 'bg-orange-100 text-orange-700' },
  urgent: { label: '紧急', class: 'bg-red-100 text-red-700' },
};

// ========== 主组件 ==========

export default function NotificationsPage() {
  const [activeTab, setActiveTab] = useState<Tab>('list');

  // 通知列表状态
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [players, setPlayers] = useState<Player[]>([]);
  const [loading, setLoading] = useState(true);
  const [unreadCount, setUnreadCount] = useState(0);
  const [filter, setFilter] = useState({ status: '', type: '', playerId: '' });
  const [selectedNotification, setSelectedNotification] = useState<Notification | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  // 模板状态
  const [templates, setTemplates] = useState<NotificationTemplate[]>([]);
  const [templateLoading, setTemplateLoading] = useState(false);
  const [showTemplateModal, setShowTemplateModal] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState<NotificationTemplate | null>(null);

  // 统计状态
  const [stats, setStats] = useState<NotificationStats | null>(null);
  const [statsLoading, setStatsLoading] = useState(false);

  // 新建通知表单
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newNotification, setNewNotification] = useState({
    playerId: '',
    guardianName: '',
    title: '',
    content: '',
    type: 'system',
  });

  // 批量发送状态
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [bulkForm, setBulkForm] = useState({
    selectedPlayerIds: [] as string[],
    title: '',
    content: '',
    type: 'system',
  });
  const [sending, setSending] = useState(false);

  // ========== 通知列表逻辑 ==========

  const fetchNotifications = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filter.status) params.set('status', filter.status);
      if (filter.type) params.set('type', filter.type);
      if (filter.playerId) params.set('playerId', filter.playerId);

      const res = await fetchWithAuth(`/api/notifications?${params}`);
      const data = await res.json();
      setNotifications(data.notifications || []);
      setUnreadCount(data.unreadCount || 0);
    } catch (error) {
      console.error('获取通知失败:', error);
    }
    setLoading(false);
  }, [filter]);

  const fetchPlayers = useCallback(async () => {
    try {
      const res = await fetchWithAuth('/api/players?status=training');
      const data = await res.json();
      setPlayers(data.players || []);
    } catch (error) {
      console.error('获取学员失败:', error);
    }
  }, []);

  useEffect(() => {
    fetchNotifications();
    fetchPlayers();
  }, [filter, fetchNotifications, fetchPlayers]);

  const handleCreateNotification = async () => {
    try {
      const res = await fetchWithAuth('/api/notifications', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newNotification),
      });
      if (res.ok) {
        setShowCreateModal(false);
        setNewNotification({
          playerId: '',
          guardianName: '',
          title: '',
          content: '',
          type: 'system',
        });
        fetchNotifications();
      }
    } catch (error) {
      console.error('创建通知失败:', error);
    }
  };

  const handleBulkSend = async () => {
    if (bulkForm.selectedPlayerIds.length === 0 || !bulkForm.title || !bulkForm.content) return;
    setSending(true);
    try {
      const res = await fetchWithAuth('/api/notifications/trigger/bulk', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bulkForm),
      });
      if (res.ok) {
        const data = await res.json();
        alert(`发送成功！${data.message}`);
        setShowBulkModal(false);
        setBulkForm({ selectedPlayerIds: [], title: '', content: '', type: 'system' });
        fetchNotifications();
      }
    } catch (error) {
      console.error('批量发送失败:', error);
    }
    setSending(false);
  };

  const handleMarkAsRead = async (notification: Notification) => {
    if (notification.status === 'read') return;
    try {
      await fetchWithAuth(`/api/notifications/${notification.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: 'read' }),
      });
      fetchNotifications();
    } catch (error) {
      console.error('标记已读失败:', error);
    }
  };

  const handleDelete = async (notification: Notification) => {
    if (!confirm('确定要删除该通知吗？')) return;
    try {
      await fetchWithAuth(`/api/notifications/${notification.id}`, { method: 'DELETE' });
      fetchNotifications();
    } catch (error) {
      console.error('删除通知失败:', error);
    }
  };

  const handleSendReminder = async () => {
    try {
      const res = await fetchWithAuth('/api/notifications/check');
      const data = await res.json();
      alert(data.summary || '检查完成');
      fetchNotifications();
    } catch (error) {
      console.error('发送提醒失败:', error);
    }
  };

  const openDetailModal = (notification: Notification) => {
    setSelectedNotification(notification);
    setShowDetailModal(true);
    if (notification.status !== 'read') {
      handleMarkAsRead(notification);
    }
  };

  // ========== 模板逻辑 ==========

  const fetchTemplates = useCallback(async () => {
    setTemplateLoading(true);
    try {
      const res = await fetchWithAuth('/api/notification-templates');
      const data = await res.json();
      setTemplates(data.templates || []);
    } catch (error) {
      console.error('获取模板失败:', error);
    }
    setTemplateLoading(false);
  }, []);

