                  placeholder={'输入通知内容，支持 {{playerName}} 变量自动替换学员姓名'}
                />
              </div>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3">
              <button
                onClick={() => setShowBulkModal(false)}
                className="px-4 py-2 border rounded-lg hover:bg-gray-100"
              >
                取消
              </button>
              <button
                onClick={handleBulkSend}
                disabled={sending || bulkForm.selectedPlayerIds.length === 0}
                className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2"
              >
                {sending ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent" />
                    发送中...
                  </>
                ) : (
                  <>
                    <Send className="w-4 h-4" /> 批量发送 ({bulkForm.selectedPlayerIds.length})
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ========== 模态框: 通知详情 ========== */}
      {showDetailModal && selectedNotification && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-lg m-4">
            <div className="border-b px-6 py-4">
              <h2 className="text-xl font-bold">通知详情</h2>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-500 mb-1">标题</label>
                <p className="text-gray-900">{selectedNotification.title}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-500 mb-1">内容</label>
                <p className="text-gray-900 whitespace-pre-wrap">{selectedNotification.content}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">类型</label>
                  <span
                    className={`px-2 py-0.5 rounded text-xs ${(typeConfig[selectedNotification.type] || typeConfig.system).class}`}
                  >
                    {(typeConfig[selectedNotification.type] || typeConfig.system).label}
                  </span>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">状态</label>
                  <span
                    className={`px-2 py-0.5 rounded text-xs ${(statusConfig[selectedNotification.status] || statusConfig.pending).class}`}
                  >
                    {(statusConfig[selectedNotification.status] || statusConfig.pending).label}
                  </span>
                </div>
              </div>
              {selectedNotification.player && (
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">学员</label>
                  <p className="text-gray-900">{selectedNotification.player.name}</p>
                </div>
              )}
              {selectedNotification.guardianName && (
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">监护人</label>
                  <p className="text-gray-900">{selectedNotification.guardianName}</p>
                </div>
              )}
              {selectedNotification.template && (
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">关联模板</label>
                  <p className="text-gray-900">{selectedNotification.template.name}</p>
                </div>
              )}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">发送时间</label>
                  <p className="text-gray-900">
                    {selectedNotification.sentAt
                      ? new Date(selectedNotification.sentAt).toLocaleString()
                      : '-'}
                  </p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500 mb-1">阅读时间</label>
                  <p className="text-gray-900">
                    {selectedNotification.readAt
                      ? new Date(selectedNotification.readAt).toLocaleString()
                      : '-'}
                  </p>
                </div>
              </div>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end">
              <button
                onClick={() => setShowDetailModal(false)}
                className="px-4 py-2 border rounded-lg hover:bg-gray-100"
              >
                关闭
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ========== 模态框: 编辑模板 ========== */}
      {showTemplateModal && editingTemplate && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-lg m-4">
            <div className="border-b px-6 py-4">
              <h2 className="text-xl font-bold">编辑模板: {editingTemplate.name}</h2>
            </div>
            <div className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">模板名称</label>
                <input
                  type="text"
                  value={editingTemplate.name}
                  onChange={(e) => setEditingTemplate({ ...editingTemplate, name: e.target.value })}
                  className="w-full px-3 py-2 border rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">通知标题</label>
                <input
                  type="text"
                  value={editingTemplate.title}
                  onChange={(e) =>
                    setEditingTemplate({ ...editingTemplate, title: e.target.value })
                  }
                  className="w-full px-3 py-2 border rounded-lg"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">通知内容</label>
                <textarea
                  value={editingTemplate.content}
                  onChange={(e) =>
                    setEditingTemplate({ ...editingTemplate, content: e.target.value })
                  }
                  className="w-full px-3 py-2 border rounded-lg font-mono text-sm"
                  rows={5}
                />
                <p className="text-xs text-gray-400 mt-1">
                  {'支持变量: {{guardianName}}, {{playerName}}, {{courseName}} 等'}
                </p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">分类</label>
                <select
                  value={editingTemplate.category}
                  onChange={(e) =>
                    setEditingTemplate({ ...editingTemplate, category: e.target.value })
                  }
                  className="w-full px-3 py-2 border rounded-lg"
                >
                  <option value="system">系统</option>
                  <option value="course">课程</option>
                  <option value="reminder">提醒</option>
                  <option value="marketing">营销</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">优先级</label>
                <select
                  value={editingTemplate.priority}
                  onChange={(e) =>
                    setEditingTemplate({ ...editingTemplate, priority: e.target.value })
                  }
                  className="w-full px-3 py-2 border rounded-lg"
                >
                  <option value="low">低</option>
                  <option value="normal">普通</option>
                  <option value="high">高</option>
                  <option value="urgent">紧急</option>
                </select>
              </div>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3">
              <button
                onClick={() => {
                  setShowTemplateModal(false);
                  setEditingTemplate(null);
                }}
                className="px-4 py-2 border rounded-lg hover:bg-gray-100"
              >
                取消
              </button>
              <button
                onClick={handleSaveTemplate}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
              >
                <Send className="w-4 h-4" /> 保存
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import Link from 'next/link';
import { fetchWithAuth } from '@/lib/auth';
import { useCloudVoiceRecognition } from '@/hooks/useCloudVoiceRecognition';
import {
  ArrowLeft,
  Plus,
  Save,
  Calendar,
  Clock,
  MapPin,
  Sun,
  Cloud,
  CloudRain,
  Snowflake,
  Sparkles,
  ChevronDown,
  ChevronUp,
  Mic,
  MicOff,
  Search,
  X,
  Users,
  Check,
} from 'lucide-react';

import {
  generateTrainingPlan,
  type AgeGroup,
  type Location,
  type TrainingPlanOutput,
  type PlanSection,
} from '@/lib/plan-generator';

// 学员类型
interface Player {
  id: string;
  name: string;
  group: string;
  age: number;
  status: string;
}

export default function NewPlanPage() {
  const [generating, setGenerating] = useState(false);
  const [saving, setSaving] = useState(false);
  const [plan, setPlan] = useState<TrainingPlanOutput | null>(null);
  const [useAI, setUseAI] = useState(false); // 是否使用AI生成
  const [configCollapsed, setConfigCollapsed] = useState(false); // 配置面板折叠状态

  // 学员选择状态
  const [allPlayers, setAllPlayers] = useState<Player[]>([]);
  const [selectedPlayerIds, setSelectedPlayerIds] = useState<string[]>([]);
  const [playerSearch, setPlayerSearch] = useState('');
  const [showPlayerDropdown, setShowPlayerDropdown] = useState(false);
  const [voiceMatchResult, setVoiceMatchResult] = useState<{
    matched: Player[];
    unmatched: string[];
  } | null>(null);
  const playerDropdownRef = useRef<HTMLDivElement>(null);

  // 语音识别
  const voice = useCloudVoiceRecognition();

  // 表单状态
  const [form, setForm] = useState({
    group: 'U10' as AgeGroup,
    duration: 90,
    location: '室内' as Location,
    weather: '',
    themes: [] as string[],
  });

  // AI特有配置
  const [aiConfig, setAiConfig] = useState({
    additionalNotes: '',
    playerCount: '',
    skillLevel: 'intermediate' as 'beginner' | 'intermediate' | 'advanced',
    intensity: 'medium' as 'low' | 'medium' | 'high',
    previousTraining: '',
    enableWeaknessAnalysis: false, // 是否根据学员薄弱环节生成教案
  });

  const [focusSkills, setFocusSkills] = useState<string[]>([]);

  // 模板选择状态
  const [showTemplateModal, setShowTemplateModal] = useState(false);
  const [templates, setTemplates] = useState<
    Array<{
      id: string;
      title: string;
      group: string;
      theme?: string;
      duration: number;
      location: string;
      skillLevel?: string;
      sections?: string;
    }>
  >([]);

  // 加载学员列表
  useEffect(() => {
    async function loadPlayers() {
      try {
        const res = await fetchWithAuth('/api/players?status=training&limit=200');
        const data = await res.json();
        if (data.success) {
          setAllPlayers(data.players);
        }
      } catch (err) {
        console.error('加载学员列表失败:', err);
      }
    }
    loadPlayers();
  }, []);

  // 加载模板列表
  useEffect(() => {
    async function loadTemplates() {
      try {
        const res = await fetchWithAuth('/api/plans?template=true&limit=20');
        const data = await res.json();
        if (data.success) {
          setTemplates(data.plans || []);
        }
      } catch (err) {
        console.error('加载模板列表失败:', err);
      }
    }
    loadTemplates();
  }, []);

  // 根据年龄段过滤学员
  const filteredPlayers = allPlayers.filter(
    (p) => p.group === form.group && p.name.includes(playerSearch)
  );

  // 已选学员对象
  const selectedPlayers = allPlayers.filter((p) => selectedPlayerIds.includes(p.id));

  // 点击外部关闭下拉
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (playerDropdownRef.current && !playerDropdownRef.current.contains(e.target as Node)) {
        setShowPlayerDropdown(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // 切换学员选中
  function togglePlayer(playerId: string) {
    setSelectedPlayerIds((prev) =>
      prev.includes(playerId) ? prev.filter((id) => id !== playerId) : [...prev, playerId]
    );
  }

  // 语音录入学员
  const handleVoicePlayerInput = useCallback(async () => {
    try {
      await voice.startRecording();
    } catch (err) {
      console.error('启动录音失败:', err);
    }
  }, [voice]);

  useEffect(() => {
    if (!voice.transcript) return;

    // 解析语音识别结果中的学员名字
    // 支持多种分隔符：顿号、逗号、空格、"和"、"跟"
    const text = voice.transcript;
    const nameParts = text
      .replace(/[，、,，]/g, ' ')
      .replace(/[和跟与及]/g, ' ')
      .replace(/今天上课|今天来|到了|参加|上课/g, '')
      .split(/\s+/)
      .map((s) => s.trim())
      .filter((s) => s.length >= 1 && s.length <= 5); // 名字长度1-5

    if (nameParts.length === 0) return;

    // 在当前年龄段的学员中匹配
    const groupPlayers = allPlayers.filter((p) => p.group === form.group);
    const matched: Player[] = [];
    const unmatched: string[] = [];

    for (const name of nameParts) {
      const found = groupPlayers.find((p) => p.name === name);
      if (found) {
        if (!matched.some((m) => m.id === found.id)) {
          matched.push(found);
        }
      } else {
        // 模糊匹配
        const fuzzy = groupPlayers.find((p) => p.name.includes(name) || name.includes(p.name));
        if (fuzzy) {
          if (!matched.some((m) => m.id === fuzzy.id)) {
            matched.push(fuzzy);
          }
        } else {
          if (!unmatched.includes(name)) {
            unmatched.push(name);
          }
        }
      }
    }

    setVoiceMatchResult({ matched, unmatched });

    // 自动选中的学员
    if (matched.length > 0) {
      setSelectedPlayerIds((prev) => {
        const newIds = new Set(prev);
        matched.forEach((p) => newIds.add(p.id));
        return Array.from(newIds);
      });
    }
  }, [voice.transcript, allPlayers, form.group]);

  // 当学员人数变化时，同步到AI配置
  useEffect(() => {
    if (selectedPlayerIds.length > 0) {
      setAiConfig((prev) => ({ ...prev, playerCount: String(selectedPlayerIds.length) }));
    }
  }, [selectedPlayerIds]);

  const groups: { id: AgeGroup; name: string; age: string; desc: string }[] = [
    { id: 'U6', name: 'U6 幼儿班', age: '4-6岁', desc: '游戏为主 球性培养' },
    {
      id: 'U8',
      name: 'U8 小学低年级',
      age: '7-8岁',
      desc: '基础运球 传球入门',
    },
    {
      id: 'U10',
      name: 'U10 小学中年级',
      age: '9-10岁',
      desc: '技术规范 体能加入',
    },
    {
      id: 'U12',
      name: 'U12 小学高年级',
      age: '11-12岁',
      desc: '战术训练 对抗加强',
    },
    { id: 'U14', name: 'U14 初中', age: '13-14岁', desc: '综合提升 中考体育' },
  ];

  const durations = [60, 90, 120];
  const locations: Location[] = ['室内', '室外'];
  const weathers = ['', '晴天', '阴天', '雨天', '雪天'];
  const themes = [
    '',
    '运球基础',
    '传球技术',
    '投篮训练',
    '防守入门',
    '进攻战术',
    '防守战术',
    '体能训练',
    '综合训练',
    '对抗比赛',
    '考核评估',
    '球性熟悉',
    '中考体育',
  ];
  const skillOptions = ['运球', '传球', '投篮', '防守', '体能', '战术'];

  // 从模板创建教案
  function handleUseTemplate(template: (typeof templates)[0]) {
    try {
      // 解析模板的 sections
      let parsedSections: PlanSection[] = [];
      try {
        parsedSections = template.sections ? JSON.parse(template.sections) : [];
      } catch {
        parsedSections = [];
      }

      // 提取主题
      const themeStr = template.theme || '';
      const themeArr: string[] = themeStr ? themeStr.split('+') : [];

      // 更新表单
      setForm((f) => ({
        ...f,
        group: template.group as AgeGroup,
        duration: template.duration,
        location: template.location as Location,
        themes: themeArr,
      }));

      if (template.skillLevel) {
        setAiConfig((c) => ({
          ...c,
          skillLevel: template.skillLevel as 'beginner' | 'intermediate' | 'advanced',
        }));
      }

      // 如果模板有 sections，直接设为教案结果
      if (parsedSections.length > 0) {
        setPlan({
          title: template.title,
          group: template.group as AgeGroup,
          date: new Date().toISOString(),
          duration: template.duration,
          location: template.location as Location,
          theme: themeStr,
          focusSkills: themeArr,
          skillLevel: (template.skillLevel || 'intermediate') as
            | 'beginner'
            | 'intermediate'
            | 'advanced',
          intensity: 'medium',
          trainingProgression: '',
          sections: parsedSections,
          notes: '',
        });
      }

      setShowTemplateModal(false);
      setConfigCollapsed(false);
    } catch (err) {
      console.error('使用模板失败:', err);
      alert('使用模板失败');
    }
  }

  // 生成教案
  async function handleGenerate() {
    setGenerating(true);

    try {
      let result: TrainingPlanOutput;

      if (useAI) {
        // AI生成（通过服务端API代理）
        const aiParams = {
          group: form.group,
          duration: form.duration,
          location: form.location,
          weather: form.weather || undefined,
          theme: form.themes.length > 0 ? form.themes.join('+') : undefined,
          focusSkills,
          additionalNotes: aiConfig.additionalNotes || undefined,
          playerCount:
            selectedPlayerIds.length > 0
              ? selectedPlayerIds.length
              : aiConfig.playerCount
                ? parseInt(aiConfig.playerCount)
                : undefined,
          skillLevel: aiConfig.skillLevel,
          intensity: aiConfig.intensity,
          previousTraining: aiConfig.previousTraining
            ? aiConfig.previousTraining.split(/[,，]/).map((s) => s.trim())
            : undefined,
          // 传递选中学员ID（仅开关开启且有学员时）
          playerIds:
            aiConfig.enableWeaknessAnalysis && selectedPlayerIds.length > 0
              ? selectedPlayerIds
              : undefined,
        };

        // 调用服务端API生成教案
        const response = await fetchWithAuth('/api/generate-plan', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(aiParams),
        });
        const data = await response.json();
        if (!data.success) {
          throw new Error(data.error || 'AI生成失败');
        }
        result = data.plan;
      } else {
        // 规则引擎生成
        await new Promise((resolve) => setTimeout(resolve, 800));
        result = generateTrainingPlan({
          group: form.group,
          duration: form.duration,
          location: form.location,
          weather: form.weather || undefined,
          theme: form.themes.length > 0 ? form.themes.join('+') : undefined,
          focusSkills,
        });
      }

      setPlan(result);
    } catch (error) {
      console.error('生成教案失败:', error);
      alert('生成教案失败，请重试');
    } finally {
      setGenerating(false);
    }
  }

  // 保存教案
  async function handleSave() {
    if (!plan) return;

    setSaving(true);

    try {
      const response = await fetchWithAuth('/api/plans', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...plan,
          generatedBy: useAI ? 'ai' : 'rule',
          playerIds: selectedPlayerIds,
        }),
      });

      const data = await response.json();

      if (data.success) {
        const msg =
          selectedPlayerIds.length > 0
            ? `教案保存成功！已为 ${data.attendanceCount} 名学员自动签到`
            : '教案保存成功！';
        alert(msg);
        // 跳转到教案详情页
        window.location.href = `/plans/${data.id}`;
      } else {
        alert('保存失败：' + data.error);
      }
    } catch (error) {
      console.error('保存教案失败:', error);
      alert('保存教案失败，请重试');
    } finally {
      setSaving(false);
    }
  }

  // 技能选择切换
  function toggleSkill(skill: string) {
    setFocusSkills((prev) =>
      prev.includes(skill) ? prev.filter((s) => s !== skill) : [...prev, skill]
    );
  }

  // 获取天气图标
  const getWeatherIcon = (w: string) => {
    switch (w) {
      case '晴天':
        return <Sun className="w-5 h-5 text-yellow-500" />;
      case '阴天':
        return <Cloud className="w-5 h-5 text-gray-500" />;
      case '雨天':
        return <CloudRain className="w-5 h-5 text-blue-500" />;
      case '雪天':
        return <Snowflake className="w-5 h-5 text-blue-300" />;
      default:
        return null;
    }
  };

  // 获取环节颜色
  const getSectionColor = (category: string) => {
    switch (category) {
      case 'warmup':
        return 'bg-yellow-100 border-yellow-300 text-yellow-800';
      case 'ball_familiarity':
        return 'bg-amber-100 border-amber-300 text-amber-800';
      case 'technical':
        return 'bg-blue-100 border-blue-300 text-blue-800';
      case 'physical':
        return 'bg-orange-100 border-orange-300 text-orange-800';
      case 'tactical':
        return 'bg-purple-100 border-purple-300 text-purple-800';
      case 'game':
        return 'bg-red-100 border-red-300 text-red-800';
      case 'cooldown':
        return 'bg-green-100 border-green-300 text-green-800';
      case 'etiquette':
        return 'bg-pink-100 border-pink-300 text-pink-800';
      default:
        return 'bg-gray-100 border-gray-300 text-gray-800';
    }
  };

  // 获取环节名称
  const getSectionLabel = (category: string) => {
    const labels: Record<string, string> = {
      warmup: '热身',
      ball_familiarity: '球性',
      technical: '技术',
      physical: '体能',
      tactical: '战术',
      game: '对抗',
      cooldown: '放松',
      etiquette: '礼仪',
    };
    return labels[category] || category;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 py-4">
          <div className="flex items-center gap-4">
            <Link href="/" className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5 text-gray-600" />
            </Link>
            <h1 className="text-xl font-bold text-gray-900">生成新教案</h1>
          </div>
        </div>
      </header>

