                {/* 训练内容 */}
                <div className="p-6 space-y-4">
                  {plan.sections.map((section, idx) => (
                    <div
                      key={idx}
                      className={`rounded-lg border-2 p-4 ${getSectionColor(section.category)}`}
                    >
                      <div className="flex items-center justify-between mb-3">
                        <h3 className="font-bold text-lg">{section.name}</h3>
                        <span className="text-sm font-medium bg-white/50 px-2 py-1 rounded">
                          {section.duration}分钟
                        </span>
                      </div>

                      {/* 第一节显示训练递进说明（仅在第一节顶部显示一次） */}
                      {idx === 0 && plan.trainingProgression && (
                        <div className="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
                          <div className="text-sm font-medium text-blue-800 mb-2">
                            📈 训练递进关联说明
                          </div>
                          <div className="text-xs text-blue-700 whitespace-pre-line leading-relaxed">
                            {plan.trainingProgression}
                          </div>
                        </div>
                      )}

                      <div className="space-y-3">
                        {section.activities.map((activity, aIdx) => (
                          <div key={aIdx} className="bg-white/60 rounded-lg p-3">
                            <div className="flex items-center justify-between mb-1">
                              <span className="font-medium">{activity.name}</span>
                              <span className="text-sm text-gray-500">{activity.duration}分钟</span>
                            </div>
                            <p className="text-sm text-gray-600 mb-2">{activity.description}</p>

                            {/* 关联提示 - 在热身为后面的训练做准备时显示 */}
                            {activity.relatedTo && (
                              <div className="mt-1 mb-2">
                                <span className="text-xs text-blue-600 bg-blue-50 px-2 py-1 rounded">
                                  💡 {activity.relatedTo}
                                </span>
                              </div>
                            )}
                            {activity.keyPoints && activity.keyPoints.length > 0 && (
                              <div className="flex flex-wrap gap-1 mt-2">
                                {activity.keyPoints.map((point, pIdx) => (
                                  <span
                                    key={pIdx}
                                    className="text-xs px-2 py-0.5 bg-blue-100 text-blue-700 rounded"
                                  >
                                    {point}
                                  </span>
                                ))}
                              </div>
                            )}
                            {activity.equipment && activity.equipment.length > 0 && (
                              <div className="text-xs text-gray-500 mt-1">
                                器材：{activity.equipment.join('、')}
                              </div>
                            )}

                            {/* 动作图解 */}
                            {activity.drillDiagram && (
                              <div className="mt-3 bg-white rounded-lg border border-gray-200 p-3">
                                <div className="text-xs font-medium text-gray-600 mb-2">
                                  动作路线示意图
                                </div>
                                <div
                                  className="flex justify-center"
                                  dangerouslySetInnerHTML={{ __html: activity.drillDiagram }}
                                />
                              </div>
                            )}

                            {/* 组数、次数、递进式 */}
                            {(activity.sets || activity.repetitions || activity.progression) && (
                              <div className="mt-3 grid grid-cols-1 gap-2 text-xs">
                                {activity.sets && (
                                  <div className="flex items-center gap-2">
                                    <span className="font-medium text-gray-700">组数：</span>
                                    <span className="text-gray-600">{activity.sets}</span>
                                  </div>
                                )}
                                {activity.repetitions && (
                                  <div className="flex items-center gap-2">
                                    <span className="font-medium text-gray-700">次数/时间：</span>
                                    <span className="text-gray-600">{activity.repetitions}</span>
                                  </div>
                                )}
                                {activity.progression && (
                                  <div className="mt-1">
                                    <div className="font-medium text-gray-700 mb-1">
                                      递进式设计：
                                    </div>
                                    <div className="text-gray-600 whitespace-pre-line">
                                      {activity.progression}
                                    </div>
                                  </div>
                                )}
                              </div>
                            )}
                          </div>
                        ))}
                      </div>

                      {section.points && section.points.length > 0 && (
                        <div className="mt-3 pt-3 border-t border-black/10">
                          <p className="text-sm font-medium">重点：{section.points.join(' · ')}</p>
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                {/* 备注 */}
                {plan.notes && (
                  <div className="p-6 bg-gray-50 border-t border-gray-100">
                    <h3 className="font-semibold text-gray-900 mb-2">注意事项</h3>
                    <p className="text-sm text-gray-600">{plan.notes}</p>
                  </div>
                )}

                {/* 操作按钮 */}
                <div className="p-6 border-t border-gray-100 flex gap-3">
                  <button
                    onClick={handleSave}
                    disabled={saving}
                    className="flex-1 py-3 bg-orange-500 hover:bg-orange-600 text-white font-semibold rounded-lg transition-colors flex items-center justify-center gap-2 disabled:opacity-50"
                  >
                    {saving ? (
                      <>保存中...</>
                    ) : (
                      <>
                        <Save className="w-5 h-5" />
                        {selectedPlayerIds.length > 0
                          ? `保存教案并签到（${selectedPlayerIds.length}人）`
                          : '保存教案'}
                      </>
                    )}
                  </button>
                  <button className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-semibold rounded-lg transition-colors">
                    导出PDF
                  </button>
                </div>
              </div>
            ) : (
              <div className="bg-white rounded-xl p-12 shadow-sm border border-gray-100 text-center">
                <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                  <Calendar className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-semibold text-gray-900 mb-2">等待生成教案</h3>
                <p className="text-gray-500 mb-4">
                  请在左侧配置训练参数
                  <br />
                  然后点击"生成教案"
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* 从模板创建 - 模态框 */}
      {showTemplateModal && (
        <>
          <div
            className="fixed inset-0 bg-black/50 z-50"
            onClick={() => setShowTemplateModal(false)}
          />
          <div className="fixed inset-x-4 top-[10%] bottom-[10%] bg-white rounded-2xl shadow-2xl z-50 flex flex-col overflow-hidden mx-auto max-w-2xl">
            <div className="p-4 border-b border-gray-100 flex items-center justify-between shrink-0">
              <h3 className="font-semibold text-gray-900">选择教案模板</h3>
              <button
                onClick={() => setShowTemplateModal(false)}
                className="p-2 hover:bg-gray-100 rounded-lg"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>
            <div className="flex-1 overflow-y-auto p-4">
              {templates.length === 0 ? (
                <div className="text-center py-12">
                  <Sparkles className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                  <p className="text-gray-500 mb-2">暂无模板</p>
                  <p className="text-sm text-gray-400">在教案详情页点击「存为模板」即可创建模板</p>
                  <button
                    onClick={() => setShowTemplateModal(false)}
                    className="mt-4 px-4 py-2 bg-orange-500 text-white rounded-lg text-sm hover:bg-orange-600"
                  >
                    返回
                  </button>
                </div>
              ) : (
                <div className="space-y-2">
                  {templates.map((tpl) => (
                    <button
                      key={tpl.id}
                      onClick={() => handleUseTemplate(tpl)}
                      className="w-full p-4 rounded-xl text-left border border-gray-200 hover:border-purple-300 hover:bg-purple-50 transition-all"
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0">
                          <div className="font-medium text-gray-900 truncate">{tpl.title}</div>
                          <div className="flex items-center gap-2 mt-1 text-sm text-gray-500">
                            <span className="px-1.5 py-0.5 bg-orange-100 text-orange-700 text-xs rounded">
                              {tpl.group}
                            </span>
                            <span>{tpl.duration}分钟</span>
                            <span>{tpl.location}</span>
                            {tpl.theme && <span>· {tpl.theme}</span>}
                          </div>
                        </div>
                        <div className="flex items-center gap-1 text-purple-500 shrink-0 ml-2">
                          <Check className="w-4 h-4" />
                          <span className="text-sm">使用</span>
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  Save,
  Clock,
  MapPin,
  Calendar,
  Plus,
  Trash2,
  GripVertical,
  ChevronDown,
} from 'lucide-react';

type Activity = {
  name: string;
  duration: number;
  description: string;
  keyPoints?: string[];
  equipment?: string[];
  coachGuide?: string;
  [key: string]: unknown;
};

type Section = {
  category: string;
  name: string;
  duration: number;
  activities: Activity[];
  points?: string[];
  [key: string]: unknown;
};

type TrainingPlan = {
  id: string;
  title: string;
  group: string;
  date: string;
  duration: number;
  location: string;
  weather?: string;
  theme?: string;
  focusSkills?: string;
  intensity?: string;
  status?: string;
  sections?: string;
  notes?: string;
};

const categories = [
  { id: 'warmup', label: '热身', color: 'bg-yellow-100 text-yellow-700' },
  {
    id: 'ball_familiarity',
    label: '球性',
    color: 'bg-amber-100 text-amber-700',
  },
  { id: 'technical', label: '技术', color: 'bg-blue-100 text-blue-700' },
  { id: 'physical', label: '体能', color: 'bg-orange-100 text-orange-700' },
  { id: 'tactical', label: '战术', color: 'bg-purple-100 text-purple-700' },
  { id: 'game', label: '对抗', color: 'bg-red-100 text-red-700' },
  { id: 'cooldown', label: '放松', color: 'bg-green-100 text-green-700' },
];

export default function EditPlanPage({ params }: { params: { id: string } }) {
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [plan, setPlan] = useState<TrainingPlan | null>(null);
  const [sections, setSections] = useState<Section[]>([]);

  // 表单状态
  const [form, setForm] = useState({
    title: '',
    date: '',
    duration: 90,
    location: '室内',
    weather: '',
    theme: '',
    intensity: 'medium',
    notes: '',
  });

  const fetchPlan = useCallback(async () => {
    try {
      const response = await fetchWithAuth(`/api/plans/${params.id}`);
      const data = await response.json();

      if (data.success) {
        const p = data.plan;
        setPlan(p);
        setForm({
          title: p.title || '',
          date: p.date ? p.date.split('T')[0] : '',
          duration: p.duration || 90,
          location: p.location || '室内',
          weather: p.weather || '',
          theme: p.theme || '',
          intensity: p.intensity || 'medium',
          notes: p.notes || '',
        });
        setSections(p.sections ? JSON.parse(p.sections) : []);
      }
    } catch (error) {
      console.error('获取教案失败:', error);
      alert('获取教案失败');
    } finally {
      setLoading(false);
    }
  }, [params.id]);

  useEffect(() => {
    fetchPlan();
  }, [fetchPlan]);

  // 添加环节
  function addSection() {
    setSections([
      ...sections,
      {
        category: 'warmup',
        name: '',
        duration: 10,
        activities: [],
      },
    ]);
  }

  // 删除环节
  function removeSection(index: number) {
    setSections(sections.filter((_, i) => i !== index));
  }

  // 更新环节
  function updateSection(index: number, field: string, value: unknown) {
    const newSections = [...sections];
    newSections[index][field as keyof Section] = value as never;
    setSections(newSections);
  }

  // 添加活动
  function addActivity(sectionIndex: number) {
    const newSections = [...sections];
    newSections[sectionIndex].activities.push({
      name: '',
      duration: 5,
      description: '',
    });
    setSections(newSections);
  }

  // 删除活动
  function removeActivity(sectionIndex: number, activityIndex: number) {
    const newSections = [...sections];
    newSections[sectionIndex].activities.splice(activityIndex, 1);
    setSections(newSections);
  }

  // 更新活动
  function updateActivity(
    sectionIndex: number,
    activityIndex: number,
    field: string,
    value: unknown
  ) {
    const newSections = [...sections];
    newSections[sectionIndex].activities[activityIndex][field as keyof Activity] = value as never;
    setSections(newSections);
  }

  // 保存
  async function handleSave() {
    if (!form.title) {
      alert('请输入教案标题');
      return;
    }

    setSaving(true);

    try {
      const response = await fetchWithAuth(`/api/plans/${params.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: form.title,
          date: form.date,
          duration: form.duration,
          location: form.location,
          weather: form.weather || null,
          theme: form.theme || null,
          intensity: form.intensity,
          notes: form.notes || null,
          sections: JSON.stringify(sections),
        }),
      });

      const data = await response.json();

      if (data.success) {
        alert('保存成功！');
        router.push(`/plans/${params.id}`);
      } else {
        alert('保存失败：' + data.error);
      }
    } catch (error) {
      console.error('保存失败:', error);
      alert('保存失败');
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  if (!plan) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-xl font-bold text-gray-900 mb-2">教案不存在</h2>
          <Link href="/plans" className="text-orange-600 hover:text-orange-700">
            返回教案库
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href={`/plans/${params.id}`} className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </Link>
              <div>
                <h1 className="text-xl font-bold text-gray-900">编辑教案</h1>
                <p className="text-sm text-gray-500">修改教案内容</p>
              </div>
            </div>
            <button
              onClick={handleSave}
              disabled={saving}
              className="flex items-center gap-2 px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg disabled:opacity-50"
            >
              {saving ? (
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <Save className="w-4 h-4" />
              )}
              保存修改
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-6 space-y-6">
        {/* 基本信息 */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <h2 className="font-semibold text-gray-900 mb-4">基本信息</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">教案标题</label>
              <input
                type="text"
                value={form.title}
                onChange={(e) => setForm({ ...form, title: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                placeholder="输入教案标题"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">训练日期</label>
              <input
                type="date"
                value={form.date}
                onChange={(e) => setForm({ ...form, date: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">训练时长</label>
              <select
                value={form.duration}
                onChange={(e) => setForm({ ...form, duration: parseInt(e.target.value) })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              >
                <option value={60}>60分钟</option>
                <option value={90}>90分钟</option>
                <option value={120}>120分钟</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">训练场地</label>
              <select
                value={form.location}
                onChange={(e) => setForm({ ...form, location: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              >
                <option value="室内">室内</option>
                <option value="室外">室外</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">天气</label>
              <select
                value={form.weather}
                onChange={(e) => setForm({ ...form, weather: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              >
                <option value="">不限定</option>
                <option value="晴天">晴天</option>
                <option value="阴天">阴天</option>
                <option value="雨天">雨天</option>
                <option value="雪天">雪天</option>
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">训练主题</label>
              <select
                value={form.theme}
                onChange={(e) => setForm({ ...form, theme: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
              >
                <option value="">选择主题</option>
                <option value="运球基础">运球基础</option>
                <option value="传球技术">传球技术</option>
                <option value="投篮训练">投篮训练</option>
                <option value="防守入门">防守入门</option>
                <option value="进攻战术">进攻战术</option>
                <option value="体能训练">体能训练</option>
                <option value="综合训练">综合训练</option>
                <option value="对抗比赛">对抗比赛</option>
              </select>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">备注</label>
              <textarea
                value={form.notes}
                onChange={(e) => setForm({ ...form, notes: e.target.value })}
                rows={2}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                placeholder="训练注意事项..."
              />
            </div>
          </div>
        </div>

        {/* 训练内容 */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-semibold text-gray-900">训练内容</h2>
            <button
              onClick={addSection}
              className="flex items-center gap-2 px-3 py-1.5 bg-orange-500 text-white rounded-lg text-sm hover:bg-orange-600"
            >
              <Plus className="w-4 h-4" />
              添加环节
            </button>
          </div>

          {sections.length === 0 ? (
            <div className="text-center py-12 text-gray-500">
              <p>暂无训练内容</p>
              <button onClick={addSection} className="mt-2 text-orange-500 hover:text-orange-600">
                添加第一个环节
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              {sections.map((section, sectionIndex) => (
                <div key={sectionIndex} className="border border-gray-200 rounded-lg p-4">
                  <div className="flex items-center gap-4 mb-3">
                    <GripVertical className="w-5 h-5 text-gray-300" />
                    <select
                      value={section.category}
                      onChange={(e) => updateSection(sectionIndex, 'category', e.target.value)}
                      className="px-3 py-1.5 border border-gray-300 rounded-lg text-sm"
                    >
                      {categories.map((cat) => (
                        <option key={cat.id} value={cat.id}>
                          {cat.label}
                        </option>
                      ))}
                    </select>
                    <input
                      type="text"
                      value={section.name}
                      onChange={(e) => updateSection(sectionIndex, 'name', e.target.value)}
                      placeholder="环节名称"
                      className="flex-1 px-3 py-1.5 border border-gray-300 rounded-lg"
                    />
                    <div className="flex items-center gap-2">
                      <Clock className="w-4 h-4 text-gray-400" />
                      <input
                        type="number"
                        value={section.duration}
                        onChange={(e) =>
                          updateSection(sectionIndex, 'duration', parseInt(e.target.value) || 0)
                        }
                        className="w-16 px-2 py-1.5 border border-gray-300 rounded-lg text-center"
                        min={1}
                      />
                      <span className="text-gray-500 text-sm">分钟</span>
                    </div>
                    <button
                      onClick={() => removeSection(sectionIndex)}
                      className="p-1.5 hover:bg-red-50 text-red-400 rounded"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>

                  {/* 活动列表 */}
                  <div className="ml-8 space-y-2">
                    {section.activities.map((activity, activityIndex) => (
                      <div key={activityIndex} className="bg-gray-50 rounded-lg p-3">
                        <div className="flex items-center gap-3 mb-2">
                          <span className="text-xs text-gray-500 bg-gray-200 px-2 py-0.5 rounded">
                            活动 {activityIndex + 1}
                          </span>
                          <input
                            type="text"
                            value={activity.name}
                            onChange={(e) =>
                              updateActivity(sectionIndex, activityIndex, 'name', e.target.value)
                            }
                            placeholder="活动名称"
                            className="flex-1 px-2 py-1 border border-gray-300 rounded text-sm"
                          />
                          <input
                            type="number"
                            value={activity.duration}
                            onChange={(e) =>
                              updateActivity(
                                sectionIndex,
                                activityIndex,
                                'duration',
                                parseInt(e.target.value) || 0
                              )
                            }
                            className="w-16 px-2 py-1 border border-gray-300 rounded text-center text-sm"
                            min={1}
                          />
                          <span className="text-gray-500 text-xs">分钟</span>
                          <button
                            onClick={() => removeActivity(sectionIndex, activityIndex)}
                            className="p-1 hover:bg-red-50 text-red-400 rounded"
                          >
                            <Trash2 className="w-3 h-3" />
                          </button>
                        </div>
                        <textarea
                          value={activity.description}
                          onChange={(e) =>
                            updateActivity(
                              sectionIndex,
                              activityIndex,
                              'description',
                              e.target.value
                            )
                          }
                          placeholder="活动描述..."
                          rows={2}
                          className="w-full px-2 py-1 border border-gray-300 rounded text-sm"
                        />
                      </div>
                    ))}
                    <button
                      onClick={() => addActivity(sectionIndex)}
                      className="flex items-center gap-1 text-sm text-orange-500 hover:text-orange-600 mt-2"
                    >
                      <Plus className="w-4 h-4" />
                      添加活动
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  Clock,
  MapPin,
  Users,
  Target,
  Play,
  CheckCircle2,
  Download,
  Edit,
  Sparkles,
  Copy,
  UserCheck,
  UserX,
  AlertCircle,
  ClipboardList,
  Star,
  Bookmark,
  LayoutTemplate,
  Save,
} from 'lucide-react';

// 教案类型
type Section = {
  category: string;
  name: string;
  duration: number;
  activities: {
    name: string;
    duration: number;
    description: string;
    keyPoints?: string[];
    equipment?: string[];
    relatedTo?: string;
    drillDiagram?: string;
    sets?: string;
    repetitions?: string;
    progression?: string;
    coachGuide?: string;
  }[];
  points?: string[];
};

type TrainingPlan = {
  id: string;
  title: string;
  group: string;
  date: string;
  duration: number;
  location: string;
  weather?: string;
  theme?: string;
  objective?: string;
  intensity?: string;
  skillLevel?: string;
  status?: string;
  generatedBy?: string;
  sections?: Section[];
  notes?: string;
  focusSkills?: string;
  trainingProgression?: string;
  playerIds?: string;
  isFavorite?: boolean;
  isTemplate?: boolean;
};

// 学员信息
type PlayerDetail = {
  id: string;
  name: string;
  group: string;
};

// 训练记录
type TrainingRecord = {
  id: string;
  playerId: string | null;
  player: { id: string; name: string; group: string } | null;
  coachName: string | null;
  attendance: string;
  signInTime: string | null;
  performance: number | null;
  feedback: string | null;
};

export default function PlanDetailPage({ params }: { params: { id: string } }) {
  const [plan, setPlan] = useState<TrainingPlan | null>(null);
  const [loading, setLoading] = useState(true);
  const [copying, setCopying] = useState(false);
  const [playerDetails, setPlayerDetails] = useState<PlayerDetail[]>([]);
  const [records, setRecords] = useState<TrainingRecord[]>([]);

  const router = useRouter();

  const fetchPlan = useCallback(async () => {
    try {
      setLoading(true);
      const response = await fetchWithAuth(`/api/plans/${params.id}`);
      const data = await response.json();

      if (data.success) {
        setPlan(data.plan);
      }
    } catch (error) {
      console.error('获取教案失败:', error);
      alert('获取教案失败');
    } finally {
      setLoading(false);
    }
  }, [params.id]);

  useEffect(() => {
    fetchPlan();
  }, [fetchPlan]);

  // 复制教案
  async function handleCopyPlan() {
    if (!plan) return;

    try {
      setCopying(true);
      const response = await fetchWithAuth('/api/plans', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: `${plan.title} (副本)`,
          date: new Date().toISOString(),
          duration: plan.duration,
          group: plan.group,
          location: plan.location,
          weather: plan.weather,
          theme: plan.theme,
          focusSkills: plan.focusSkills ? JSON.parse(plan.focusSkills) : [],
          intensity: plan.intensity || 'medium',
          sections: plan.sections || [],
          notes: plan.notes,
          generatedBy: plan.generatedBy,
        }),
      });

      const result = await response.json();
      if (result.success) {
        alert('教案复制成功！');
        router.push(`/plans/${result.id}`);
      } else {
        alert('复制失败: ' + result.error);
      }
    } catch (error) {
      console.error('复制教案失败:', error);
      alert('复制失败');
    } finally {
      setCopying(false);
    }
  }

  // 切换收藏
  async function toggleFavorite() {
    if (!plan) return;
    try {
      const response = await fetchWithAuth(`/api/plans/${plan.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ isFavorite: !plan.isFavorite }),
      });
      const result = await response.json();
      if (result.success) {
        setPlan({ ...plan, isFavorite: !plan.isFavorite });
      }
    } catch (error) {
      console.error('切换收藏失败:', error);
    }
  }

  // 切换模板
  async function toggleTemplate() {
    if (!plan) return;
    try {
      const response = await fetchWithAuth(`/api/plans/${plan.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ isTemplate: !plan.isTemplate }),
      });
      const result = await response.json();
      if (result.success) {
        setPlan({ ...plan, isTemplate: !plan.isTemplate });
      }
    } catch (error) {
      console.error('切换模板失败:', error);
    }
  }

  // 保存为案例
  async function handleSaveAsCase() {
    if (!plan) return;

    try {
      // 把教案的 sections 展开成案例
      const casesToCreate: Array<{
        title: string;
        category: string;
        ageGroup: string;
        content: string;
        method?: string;
        keyPoints?: string;
        coachGuide?: string;
        duration: number;
        equipment: string[];
        techType?: string;
        tags: string[];
      }> = [];

      (plan.sections || []).forEach((section: Section) => {
        (section.activities || []).forEach((activity) => {
          const keyPointsStr = activity.keyPoints?.join('；') || '';
          casesToCreate.push({
            title: activity.name,
            category: section.category || 'technical',
            ageGroup: plan.group || 'U10',
            content: activity.description,
            method:
              activity.sets || activity.repetitions
                ? `组数: ${activity.sets || '-'} 次/时间: ${activity.repetitions || '-'}`
                : undefined,
            keyPoints: keyPointsStr || undefined,
            coachGuide: activity.coachGuide || undefined,
            duration: activity.duration || 10,
            equipment: activity.equipment || [],
            techType: plan.theme || undefined,
            tags: [plan.theme || '', section.category].filter(Boolean),
          });
        });
      });

      if (casesToCreate.length === 0) {
        alert('教案没有可保存的训练活动');
        return;
      }

      const response = await fetchWithAuth('/api/cases', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ cases: casesToCreate }),
      });

      const result = await response.json();
      if (result.success) {
        alert(`成功保存 ${result.imported} 个训练活动到案例库！`);
      } else {
        alert('保存失败: ' + result.error);
      }
    } catch (error) {
      console.error('保存为案例失败:', error);
      alert('保存失败');
    }
  }

  // 出勤状态图标和样式
  const getAttendanceInfo = (attendance: string) => {
    switch (attendance) {
      case 'present':
        return {
          icon: UserCheck,
          label: '已签到',
          color: 'text-green-600',
          bg: 'bg-green-50 border-green-200',
        };
      case 'absent':
        return {
          icon: UserX,
          label: '缺勤',
          color: 'text-red-600',
          bg: 'bg-red-50 border-red-200',
        };
      case 'late':
        return {
          icon: AlertCircle,
          label: '迟到',
          color: 'text-amber-600',
          bg: 'bg-amber-50 border-amber-200',
        };
      default:
        return {
          icon: UserCheck,
          label: '已签到',
          color: 'text-green-600',
          bg: 'bg-green-50 border-green-200',
        };
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  if (!plan) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-xl font-bold text-gray-900 mb-2">教案不存在</h2>
          <Link href="/plans" className="text-orange-600 hover:text-orange-700">
            返回教案库
          </Link>
        </div>
      </div>
    );
  }

  // 统计
  const totalTime = plan.duration;
  const activityCount = plan.sections?.length || 0;
  const totalPlayers = playerDetails.length;
  const presentCount = records.filter((r) => r.attendance === 'present').length;
  const lateCount = records.filter((r) => r.attendance === 'late').length;
  const absentCount = records.filter((r) => r.attendance === 'absent').length;

  // 获取环节颜色
  const getSectionColor = (category: string) => {
    switch (category) {
      case 'warmup':
        return 'bg-blue-100 text-blue-700';
      case 'ball_familiarity':
        return 'bg-amber-100 text-amber-700';
      case 'technical':
        return 'bg-orange-100 text-orange-700';
      case 'physical':
        return 'bg-red-100 text-red-700';
      case 'tactical':
        return 'bg-purple-100 text-purple-700';
      case 'game':
        return 'bg-green-100 text-green-700';
      case 'cooldown':
        return 'bg-gray-100 text-gray-700';
      case 'etiquette':
        return 'bg-pink-100 text-pink-700';
      default:
        return 'bg-gray-100 text-gray-700';
    }
  };

  const getSectionLabel = (category: string) => {
    const labels: Record<string, string> = {
      warmup: '热身',
      ball_familiarity: '球性',
      technical: '技术',
      physical: '体能',
      tactical: '战术',
      game: '对抗',
      cooldown: '放松',
      etiquette: '礼仪',
    };
    return labels[category] || category;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/plans" className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </Link>
              <div>
                <div className="flex items-center gap-2 flex-wrap">
                  <h1 className="text-xl font-bold text-gray-900">{plan.title}</h1>
                  {plan.generatedBy === 'ai' && (
                    <span className="flex items-center gap-1 px-2 py-0.5 bg-purple-100 text-purple-700 text-xs rounded-full">
                      <Sparkles className="w-3 h-3" />
                      AI生成
                    </span>
                  )}
                  {totalPlayers > 0 && (
                    <span className="flex items-center gap-1 px-2 py-0.5 bg-green-100 text-green-700 text-xs rounded-full">
                      <Users className="w-3 h-3" />
                      {totalPlayers}人
                    </span>
                  )}
                </div>
                <div className="flex items-center gap-3 text-sm text-gray-500 mt-1">
                  <span>{plan.date}</span>
                  <span className="px-2 py-0.5 bg-orange-100 text-orange-700 text-xs rounded-full">
                    {plan.group}
                  </span>
                  {plan.theme && (
                    <span className="px-2 py-0.5 bg-blue-100 text-blue-700 text-xs rounded-full">
                      {plan.theme}
                    </span>
                  )}
                  {plan.skillLevel && (
                    <span
                      className={`px-2 py-0.5 text-xs rounded-full text-white ${
                        plan.skillLevel === 'advanced'
                          ? 'bg-indigo-500'
                          : plan.skillLevel === 'intermediate'
                            ? 'bg-blue-500'
                            : 'bg-cyan-500'
                      }`}
                    >
                      {plan.skillLevel === 'advanced'
                        ? '精英'
                        : plan.skillLevel === 'intermediate'
                          ? '进阶'
                          : '基础'}
                    </span>
                  )}
                  <span
                    className={`px-2 py-0.5 text-xs rounded-full text-white ${
                      plan.intensity === 'high'
                        ? 'bg-red-600'
                        : plan.intensity === 'medium'
                          ? 'bg-yellow-600'
                          : 'bg-green-600'
                    }`}
                  >
                    {plan.intensity === 'high'
                      ? '高强度'
                      : plan.intensity === 'medium'
                        ? '中强度'
                        : '低强度'}
                  </span>
                </div>
              </div>
            </div>
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
              {/* 次要操作：图标按钮 */}
              <div className="flex items-center gap-1">
                <button
                  onClick={toggleFavorite}
                  className={`p-2 rounded-lg transition-colors ${
                    plan.isFavorite
                      ? 'text-yellow-500 hover:bg-yellow-50'
                      : 'text-gray-400 hover:bg-gray-100 hover:text-yellow-500'
                  }`}
                  title={plan.isFavorite ? '取消收藏' : '收藏'}
                >
                  <Star className={`w-5 h-5 ${plan.isFavorite ? 'fill-yellow-400' : ''}`} />
                </button>
                <button
                  onClick={toggleTemplate}
                  className={`p-2 rounded-lg transition-colors ${
                    plan.isTemplate
                      ? 'text-purple-500 hover:bg-purple-50'
                      : 'text-gray-400 hover:bg-gray-100 hover:text-purple-500'
                  }`}
                  title={plan.isTemplate ? '取消模板' : '存为模板'}
                >
                  <LayoutTemplate className="w-5 h-5" />
                </button>
                <div className="w-px h-5 bg-gray-200 mx-1" />
                <button
                  onClick={handleCopyPlan}
                  disabled={copying}
                  className="p-2 text-gray-400 hover:bg-gray-100 hover:text-gray-600 rounded-lg disabled:opacity-50"
                  title="复制"
                >
                  {copying ? (
                    <div className="w-5 h-5 border-2 border-gray-400 border-t-transparent rounded-full animate-spin" />
                  ) : (
                    <Copy className="w-5 h-5" />
                  )}
                </button>
                <Link
                  href={`/plans/${plan.id}/edit`}
                  className="p-2 text-gray-400 hover:bg-gray-100 hover:text-gray-600 rounded-lg"
                  title="编辑"
                >
                  <Edit className="w-5 h-5" />
                </Link>
                <button
                  className="p-2 text-gray-400 hover:bg-gray-100 hover:text-gray-600 rounded-lg"
                  title="导出"
                >
                  <Download className="w-5 h-5" />
                </button>
              </div>
              {/* 主要操作：文字按钮 */}
              <div className="flex items-center gap-2">
                <button
                  onClick={handleSaveAsCase}
                  className="flex items-center gap-1.5 px-4 py-2 text-sm border border-blue-300 text-blue-600 rounded-lg hover:bg-blue-50 transition-colors"
                  title="将教案中的训练活动保存到案例库"
                >
                  <Save className="w-4 h-4" />
                  <span>保存为案例</span>
                </button>
                <Link
                  href={`/training?planId=${plan.id}`}
                  className="flex items-center gap-1.5 px-4 py-2 text-sm bg-orange-500 hover:bg-orange-600 text-white rounded-lg transition-colors"
                >
                  <Play className="w-4 h-4" />
                  <span>开始训练</span>
                </Link>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* 教案概览 */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div className="flex items-center gap-3">
              <Clock className="w-5 h-5 text-orange-500" />
              <div>
                <div className="text-sm text-gray-500">训练时长</div>
                <div className="font-semibold text-gray-900">{plan.duration}分钟</div>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <MapPin className="w-5 h-5 text-blue-500" />
              <div>
                <div className="text-sm text-gray-500">训练场地</div>
                <div className="font-semibold text-gray-900">{plan.location}</div>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <Users className="w-5 h-5 text-green-500" />
              <div>
                <div className="text-sm text-gray-500">
                  {totalPlayers > 0 ? '参训人数' : '适合人数'}
                </div>
                <div className="font-semibold text-gray-900">
                  {totalPlayers > 0 ? `${totalPlayers}人` : '8-12人'}
                </div>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <Target className="w-5 h-5 text-purple-500" />
              <div>
                <div className="text-sm text-gray-500">训练内容</div>
                <div className="font-semibold text-gray-900">{activityCount}项</div>
              </div>
            </div>
          </div>

          {/* 训练目标 */}
          {plan.objective && (
            <div className="mt-6 pt-6 border-t border-gray-100">
              <h3 className="font-semibold text-gray-900 mb-2">训练目标</h3>
              <p className="text-gray-600">{plan.objective}</p>
            </div>
          )}
        </div>

        {/* 参训学员 */}
        {totalPlayers > 0 && (
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 mb-6 overflow-hidden">
            <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <ClipboardList className="w-5 h-5 text-green-600" />
                <h2 className="text-lg font-semibold text-gray-900">参训学员</h2>
              </div>
              <div className="flex items-center gap-3 text-sm">
                {presentCount > 0 && (
                  <span className="flex items-center gap-1 text-green-600">
                    <UserCheck className="w-4 h-4" />
                    {presentCount}到
                  </span>
                )}
                {lateCount > 0 && (
                  <span className="flex items-center gap-1 text-amber-600">
                    <AlertCircle className="w-4 h-4" />
                    {lateCount}迟
                  </span>
                )}
                {absentCount > 0 && (
                  <span className="flex items-center gap-1 text-red-600">
                    <UserX className="w-4 h-4" />
                    {absentCount}缺
                  </span>
                )}
              </div>
            </div>
            <div className="divide-y divide-gray-50">
              {playerDetails.map((player, idx) => {
                // 查找对应的训练记录
                const record = records.find((r) => r.playerId === player.id);
                const attendanceInfo = record ? getAttendanceInfo(record.attendance) : null;
                const AttendanceIcon = attendanceInfo?.icon || UserCheck;

                return (
                  <div
                    key={player.id}
                    className="px-6 py-3 flex items-center justify-between hover:bg-gray-50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-gradient-to-br from-orange-400 to-orange-500 flex items-center justify-center text-white text-sm font-bold">
                        {idx + 1}
                      </div>
                      <div>
                        <div className="font-medium text-gray-900">{player.name}</div>
                        <div className="text-xs text-gray-400">{player.group}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      {attendanceInfo && (
                        <span
                          className={`inline-flex items-center gap-1 px-2 py-1 text-xs rounded-full border ${attendanceInfo.bg} ${attendanceInfo.color}`}
                        >
                          <AttendanceIcon className="w-3 h-3" />
                          {attendanceInfo.label}
                        </span>
                      )}
                      {record?.feedback && (
                        <span
                          className="text-xs text-gray-400 max-w-[120px] truncate"
                          title={record.feedback}
                        >
                          {record.feedback}
                        </span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* 训练内容 */}
        <div className="space-y-4">
          <h2 className="text-lg font-semibold text-gray-900">训练内容</h2>
          {plan.sections?.map((section, index) => (
            <div
              key={index}
              className="bg-white rounded-xl p-5 shadow-sm border border-gray-100 hover:shadow-md transition-shadow"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                  <div
                    className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${getSectionColor(section.category)}`}
                  >
                    {index + 1}
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900">{section.name}</h3>
                    <span className="text-sm text-gray-500 flex items-center gap-2">
                      <Clock className="w-3 h-3" />
                      {section.duration}分钟
                      <span
                        className={`px-2 py-0.5 text-xs rounded-full ${getSectionColor(section.category)}`}
                      >
                        {getSectionLabel(section.category)}
                      </span>
                    </span>
                  </div>
                </div>
                <button className="p-2 hover:bg-gray-100 rounded-lg">
                  <CheckCircle2 className="w-5 h-5 text-gray-300" />
                </button>
              </div>

              {/* 第一节显示训练递进说明 */}
              {index === 0 && plan.trainingProgression && (
                <div className="mb-4 p-3 bg-blue-50 border border-blue-200 rounded-lg">
                  <div className="text-sm font-medium text-blue-800 mb-2">📈 训练递进关联说明</div>
                  <div className="text-xs text-blue-700 whitespace-pre-line leading-relaxed">
                    {plan.trainingProgression}
                  </div>
                </div>
              )}

              <div className="ml-11 space-y-3">
                {section.activities?.map((activity, aIdx: number) => (
                  <div key={aIdx} className="bg-gray-50 rounded-lg p-3">
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-medium text-gray-900">{activity.name}</span>
                      <span className="text-sm text-gray-500">{activity.duration}分钟</span>
                    </div>
                    <p className="text-sm text-gray-600 mb-2">{activity.description}</p>

                    {/* 关联提示 - 在热身为后面的训练做准备时显示 */}
                    {activity.relatedTo && (
                      <div className="mt-1 mb-2">
                        <span className="text-xs text-blue-600 bg-blue-50 px-2 py-1 rounded">
                          💡 {activity.relatedTo}
                        </span>
                      </div>
                    )}

                    {activity.keyPoints && activity.keyPoints.length > 0 && (
                      <div className="flex flex-wrap gap-1 mt-2">
                        {activity.keyPoints.map((point: string, pIdx: number) => (
                          <span
                            key={pIdx}
                            className="text-xs px-2 py-0.5 bg-blue-100 text-blue-700 rounded"
                          >
                            {point}
                          </span>
                        ))}
                      </div>
                    )}

                    {activity.equipment && activity.equipment.length > 0 && (
                      <div className="text-xs text-gray-500 mt-1">
                        器材：{activity.equipment.join('、')}
                      </div>
                    )}

                    {/* SVG战术图解 - 移动端可滚动 */}
                    {activity.drillDiagram && (
                      <div className="mt-3 bg-white rounded-lg border border-gray-200 p-3">
                        <div className="text-xs font-medium text-gray-600 mb-2">动作路线示意图</div>
                        <div className="overflow-x-auto -mx-2 px-2 sm:overflow-x-visible sm:mx-0 sm:px-0">
                          <div
                            className="inline-block min-w-full sm:min-w-0"
                            dangerouslySetInnerHTML={{ __html: activity.drillDiagram }}
                          />
                        </div>
                      </div>
                    )}

                    {/* 组数、次数、递进式 */}
                    {(activity.sets || activity.repetitions || activity.progression) && (
                      <div className="mt-3 grid grid-cols-1 gap-2 text-xs">
                        {activity.sets && (
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-gray-700">组数：</span>
                            <span className="text-gray-600">{activity.sets}</span>
                          </div>
                        )}
                        {activity.repetitions && (
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-gray-700">次数/时间：</span>
                            <span className="text-gray-600">{activity.repetitions}</span>
                          </div>
                        )}
                        {activity.progression && (
                          <div className="mt-1">
                            <div className="font-medium text-gray-700 mb-1">递进式设计：</div>
                            <div className="text-gray-600 whitespace-pre-line">
                              {activity.progression}
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                ))}
              </div>

              {section.points && section.points.length > 0 && (
                <div className="ml-11 mt-3 pt-3 border-t border-gray-200">
                  <p className="text-sm font-medium text-gray-700">
                    重点：{section.points.join(' · ')}
                  </p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 注意事项 */}
        {plan.notes && (
          <div className="mt-6 bg-yellow-50 rounded-xl p-5 border border-yellow-200">
            <h3 className="font-semibold text-gray-900 mb-2">注意事项</h3>
            <p className="text-sm text-gray-700">{plan.notes}</p>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  Plus,
  Search,
  Calendar,
  Clock,
  MapPin,
  Target,
  MoreVertical,
  Copy,
  Edit,
  Trash2,
  Download,
  Sparkles,
  Users,
  Star,
  Bookmark,
  LayoutTemplate,
} from 'lucide-react';

// 教案类型
type TrainingPlan = {
  id: string;
  title: string;
  date: string;
  duration: number;
  group: string;
  location: string;
  weather?: string;
  theme?: string;
  focusSkills?: string;
  intensity?: string;
  skillLevel?: string;
  status?: string;
  generatedBy?: string;
  createdAt?: string;
  sections?: string;
  playerIds?: string;
  isFavorite?: boolean;
  isTemplate?: boolean;
};

export default function PlansPage() {
  const [plans, setPlans] = useState<TrainingPlan[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [groupFilter, setGroupFilter] = useState('all');
  const [themeFilter, setThemeFilter] = useState('all');
  const [copyingId, setCopyingId] = useState<string | null>(null);
  const [favoriteFilter, setFavoriteFilter] = useState(false);
  const [templateFilter, setTemplateFilter] = useState(false);

  const router = useRouter();

  const groups = ['all', 'U6', 'U8', 'U10', 'U12', 'U14'];
  const themes = [
    'all',
    '运球基础',
    '传球技术',
    '投篮训练',
    '防守入门',
    '进攻战术',
    '体能训练',
    '综合训练',
    '对抗比赛',
  ];

  const fetchPlans = useCallback(async () => {
    try {
      setLoading(true);
      const response = await fetchWithAuth('/api/plans?limit=50');
      const data = await response.json();

      if (data.success) {
        // 解析 focusSkills
        const parsedPlans = data.plans.map((plan: TrainingPlan) => ({
          ...plan,
          focusSkills: plan.focusSkills ? JSON.parse(plan.focusSkills as string) : [],
        }));
        setPlans(parsedPlans);
      }
    } catch (error) {
      console.error('获取教案列表失败:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchPlans();
  }, [fetchPlans]);

  // 复制教案
  async function handleCopyPlan(plan: TrainingPlan, e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();

    try {
      setCopyingId(plan.id);
      const response = await fetchWithAuth('/api/plans', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: `${plan.title} (副本)`,
          date: new Date().toISOString(),
          duration: plan.duration,
          group: plan.group,
          location: plan.location,
          weather: plan.weather,
          theme: plan.theme,
          focusSkills: plan.focusSkills ? JSON.parse(plan.focusSkills) : [],
          intensity: plan.intensity || 'medium',
          skillLevel: plan.skillLevel || 'intermediate',
          sections: plan.sections ? JSON.parse(plan.sections) : [],
          notes: '',
          generatedBy: plan.generatedBy,
        }),
      });

      const result = await response.json();
      if (result.success) {
        alert('教案复制成功！');
        fetchPlans();
        // 跳转到新教案详情页
        router.push(`/plans/${result.id}`);
      } else {
        alert('复制失败: ' + result.error);
      }
    } catch (error) {
      console.error('复制教案失败:', error);
      alert('复制失败');
    } finally {
      setCopyingId(null);
    }
  }

  // 切换收藏
  async function toggleFavorite(plan: TrainingPlan, e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();

    try {
      const newValue = !plan.isFavorite;
      const response = await fetchWithAuth(`/api/plans/${plan.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ isFavorite: newValue }),
      });

      const result = await response.json();
      if (result.success) {
        setPlans((prev) =>
          prev.map((p) => (p.id === plan.id ? { ...p, isFavorite: newValue } : p))
        );
      }
    } catch (error) {
      console.error('切换收藏失败:', error);
    }
  }

  // 切换模板
  async function toggleTemplate(plan: TrainingPlan, e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();

    try {
      const newValue = !plan.isTemplate;
      const response = await fetchWithAuth(`/api/plans/${plan.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ isTemplate: newValue }),
      });

      const result = await response.json();
      if (result.success) {
        setPlans((prev) =>
          prev.map((p) => (p.id === plan.id ? { ...p, isTemplate: newValue } : p))
        );
      }
    } catch (error) {
      console.error('切换模板失败:', error);
    }
  }

  const filteredPlans = plans.filter((p) => {
    if (groupFilter !== 'all' && p.group !== groupFilter) return false;
    if (themeFilter !== 'all' && p.theme !== themeFilter) return false;
    if (favoriteFilter && !p.isFavorite) return false;
    if (templateFilter && !p.isTemplate) return false;
    if (search && !p.title.includes(search)) return false;
    return true;
  });

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/" className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </Link>
              <h1 className="text-xl font-bold text-gray-900">教案库</h1>
              <span className="text-sm text-gray-500">{filteredPlans.length}份教案</span>
            </div>
            <div className="flex items-center gap-2">
              <a
                href="/api/export?type=plans&format=excel"
                download
                className="flex items-center gap-2 px-4 py-2 border border-gray-300 hover:bg-gray-50 text-gray-700 rounded-lg"
              >
                <Download className="w-4 h-4" />
                导出
              </a>
              <Link
                href="/plan/new"
                className="flex items-center gap-2 px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg"
              >
                <Plus className="w-4 h-4" />
                新建教案
              </Link>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* 搜索和筛选 */}
        <div className="flex flex-wrap gap-4 mb-6">
          <div className="flex-1 min-w-[200px] relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="搜索教案..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
            />
          </div>

          <select
            value={groupFilter}
            onChange={(e) => setGroupFilter(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg"
          >
            {groups.map((g) => (
              <option key={g} value={g}>
                {g === 'all' ? '全部分组' : g}
              </option>
            ))}
          </select>

          <select
            value={themeFilter}
            onChange={(e) => setThemeFilter(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg"
          >
            {themes.map((t) => (
              <option key={t} value={t}>
                {t === 'all' ? '全部主题' : t}
              </option>
            ))}
          </select>

          <button
            onClick={() => setFavoriteFilter(!favoriteFilter)}
            className={`flex items-center gap-1 px-3 py-2 border rounded-lg transition-colors ${
              favoriteFilter
                ? 'border-yellow-400 bg-yellow-50 text-yellow-700'
                : 'border-gray-300 text-gray-600 hover:bg-gray-50'
            }`}
          >
            <Star
              className={`w-4 h-4 ${favoriteFilter ? 'fill-yellow-400 text-yellow-400' : ''}`}
            />
            收藏
          </button>

          <button
            onClick={() => setTemplateFilter(!templateFilter)}
            className={`flex items-center gap-1 px-3 py-2 border rounded-lg transition-colors ${
              templateFilter
                ? 'border-purple-400 bg-purple-50 text-purple-700'
                : 'border-gray-300 text-gray-600 hover:bg-gray-50'
            }`}
          >
            <LayoutTemplate className="w-4 h-4" />
            模板
          </button>
        </div>

        {/* 教案列表 */}
        <div className="space-y-3">
          {filteredPlans.map((plan) => (
            <Link
              key={plan.id}
              href={`/plans/${plan.id}`}
              className="block bg-white rounded-xl p-5 shadow-sm border border-gray-100 hover:shadow-md transition-shadow"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-bold text-lg text-gray-900">{plan.title}</h3>
                    <span className="px-2 py-0.5 bg-orange-100 text-orange-700 text-xs rounded-full">
                      {plan.group}
                    </span>
                    {plan.theme && (
                      <span className="px-2 py-0.5 bg-blue-100 text-blue-700 text-xs rounded-full">
                        {plan.theme}
                      </span>
                    )}
                    {plan.isTemplate && (
                      <span className="px-2 py-0.5 bg-purple-100 text-purple-700 text-xs rounded-full flex items-center gap-1">
                        <LayoutTemplate className="w-3 h-3" />
                        模板
                      </span>
                    )}
                    <span
                      className={`px-2 py-0.5 text-xs rounded-full text-white ${
                        plan.skillLevel === 'advanced'
                          ? 'bg-indigo-500'
                          : plan.skillLevel === 'intermediate'
                            ? 'bg-blue-500'
                            : 'bg-cyan-500'
                      }`}
                    >
                      {plan.skillLevel === 'advanced'
                        ? '精英'
                        : plan.skillLevel === 'intermediate'
                          ? '进阶'
                          : '基础'}
                    </span>
                    <span
                      className={`px-2 py-0.5 text-xs rounded-full text-white ${
                        plan.intensity === 'high'
                          ? 'bg-red-600'
                          : plan.intensity === 'medium'
                            ? 'bg-yellow-600'
                            : 'bg-green-600'
                      }`}
                    >
                      {plan.intensity === 'high'
                        ? '高强度'
                        : plan.intensity === 'medium'
                          ? '中强度'
                          : '低强度'}
                    </span>
                  </div>

                  <div className="flex items-center gap-4 text-sm text-gray-500">
                    <span className="flex items-center gap-1">
                      <Calendar className="w-4 h-4" />
                      {plan.date}
                    </span>
                    <span className="flex items-center gap-1">
                      <Clock className="w-4 h-4" />
                      {plan.duration}分钟
                    </span>
                    <span className="flex items-center gap-1">
                      <MapPin className="w-4 h-4" />
                      {plan.location}
                    </span>
                    <span className="flex items-center gap-1">
                      <Target className="w-4 h-4" />
                      {plan.sections ? JSON.parse(plan.sections).length : 0}项内容
                    </span>
                    {/* 参训人数 */}
                    {(() => {
                      try {
                        const ids = JSON.parse(plan.playerIds || '[]');
                        if (ids.length > 0) {
                          return (
                            <span className="flex items-center gap-1 text-green-600">
                              <Users className="w-4 h-4" />
                              {ids.length}人
                            </span>
                          );
                        }
                      } catch {
                        /* ignore */
                      }
                      return null;
                    })()}
                  </div>
                </div>

                {/* 操作按钮 */}
                <div className="flex items-center gap-2">
                  <button
                    onClick={(e) => toggleFavorite(plan, e)}
                    className="p-2 hover:bg-yellow-50 rounded-lg transition-colors"
                    title={plan.isFavorite ? '取消收藏' : '收藏'}
                  >
                    <Star
                      className={`w-4 h-4 ${
                        plan.isFavorite
                          ? 'fill-yellow-400 text-yellow-400'
                          : 'text-gray-300 hover:text-yellow-400'
                      }`}
                    />
                  </button>
                  <button
                    onClick={(e) => toggleTemplate(plan, e)}
                    className={`p-2 rounded-lg transition-colors ${
                      plan.isTemplate ? 'hover:bg-purple-50' : 'hover:bg-gray-100'
                    }`}
                    title={plan.isTemplate ? '取消模板' : '存为模板'}
                  >
                    <Bookmark
                      className={`w-4 h-4 ${
                        plan.isTemplate ? 'text-purple-500' : 'text-gray-300 hover:text-purple-400'
                      }`}
                    />
                  </button>
                  <button
                    onClick={(e) => handleCopyPlan(plan, e)}
                    disabled={copyingId === plan.id}
                    className="p-2 hover:bg-gray-100 rounded-lg disabled:opacity-50"
                    title="复制"
                  >
                    {copyingId === plan.id ? (
                      <div className="w-4 h-4 border-2 border-orange-500 border-t-transparent rounded-full animate-spin" />
                    ) : (
                      <Copy className="w-4 h-4 text-gray-400" />
                    )}
                  </button>
                  <button
                    onClick={(e) => e.preventDefault()}
                    className="p-2 hover:bg-gray-100 rounded-lg"
                    title="编辑"
                  >
                    <Edit className="w-4 h-4 text-gray-400" />
                  </button>
                  <button
                    onClick={(e) => e.preventDefault()}
                    className="p-2 hover:bg-gray-100 rounded-lg"
                    title="导出"
                  >
                    <Download className="w-4 h-4 text-gray-400" />
                  </button>
                  <button
                    onClick={(e) => e.preventDefault()}
                    className="p-2 hover:bg-gray-100 rounded-lg"
                    title="更多"
                  >
                    <MoreVertical className="w-4 h-4 text-gray-400" />
                  </button>
                </div>
              </div>
            </Link>
          ))}
        </div>

        {/* 空状态 */}
        {filteredPlans.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-500 mb-4">没有找到匹配的教案</p>
            <Link href="/plan/new" className="text-orange-600 hover:text-orange-700">
              创建第一份教案
            </Link>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import Link from 'next/link';
import { fetchWithAuth } from '@/lib/auth';
import {
  AlertCircle,
  ArrowLeft,
  CheckCircle,
  ChevronRight,
  Download,
  Edit2,
  FileSpreadsheet,
  MapPin,
  Phone,
  Plus,
  Search,
  Trash2,
  Upload,
  Users,
  X,
} from 'lucide-react';

// 长按功能使用原生事件实现，不再需要 @use-gesture/react

// 学员类型
type Player = {
  id: string;
  name: string;
  group: string;
  gender: string;
  birthDate: string;
  age: number;
  status: string;
  school: string;
  parentName: string;
  parentPhone: string;
  parentWechat: string;
  team: { id: string; name: string } | null;
  guardians: Guardian[];
  trainingCount: number;
  assessmentCount: number;
