const groups = ['all', 'U6', 'U8', 'U10', 'U12', 'U14'];
const statuses = [
  { value: 'all', label: '全部状态' },
  { value: 'trial', label: '试听中' },
  { value: 'training', label: '在训' },
  { value: 'vacation', label: '请假' },
  { value: 'suspended', label: '停课' },
  { value: 'graduated', label: '结业' },
];

const statusColors: Record<string, string> = {
  trial: 'bg-purple-100 text-purple-700',
  training: 'bg-green-100 text-green-700',
  vacation: 'bg-yellow-100 text-yellow-700',
  suspended: 'bg-gray-100 text-gray-700',
  graduated: 'bg-blue-100 text-blue-700',
};

const statusLabels: Record<string, string> = {
  trial: '试听',
  training: '在训',
  vacation: '请假',
  suspended: '停课',
  graduated: '结业',
};

export default function PlayersPage() {
  const [players, setPlayers] = useState<Player[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [groupFilter, setGroupFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [showImportModal, setShowImportModal] = useState(false);
  const [importResult, setImportResult] = useState<{
    success: boolean;
    total?: number;
    created?: number;
    failed?: number;
    message?: string;
    errors?: { row: number; message?: string; name?: string; error?: string; type?: string }[];
  } | null>(null);
  const [importing, setImporting] = useState(false);
  const [dragActive, setDragActive] = useState(false);

  // 长按快捷菜单
  const [longPressMenu, setLongPressMenu] = useState<{
    show: boolean;
    x: number;
    y: number;
    player: Player | null;
  }>({ show: false, x: 0, y: 0, player: null });

  // 新建/编辑表单
  const [formData, setFormData] = useState({
    name: '',
    gender: 'male',
    birthDate: '',
    group: 'U10',
    status: 'training',
    school: '',
    parentName: '',
    parentPhone: '',
    parentWechat: '',
  });

  const fetchPlayers = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (groupFilter !== 'all') params.set('group', groupFilter);
      if (statusFilter !== 'all') params.set('status', statusFilter);
      if (search) params.set('search', search);

      const response = await fetchWithAuth(`/api/players?${params}`);
      const data = await response.json();

      if (data.success) {
        setPlayers(data.players);
      }
    } catch (error) {
      console.error('获取学员列表失败:', error);
    } finally {
      setLoading(false);
    }
  }, [groupFilter, statusFilter, search]);

  useEffect(() => {
    fetchPlayers();
  }, [fetchPlayers]);

  useEffect(() => {
    fetchPlayers();
  }, [groupFilter, statusFilter, fetchPlayers]);

  const handleSearch = () => {
    fetchPlayers();
  };

  const handleAddPlayer = async () => {
    if (!formData.name || !formData.birthDate) {
      alert('请填写姓名和出生日期');
      return;
    }

    try {
      const response = await fetchWithAuth('/api/players', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (data.success) {
        setShowAddModal(false);
        setFormData({
          name: '',
          gender: 'male',
          birthDate: '',
          group: 'U10',
          status: 'training',
          school: '',
          parentName: '',
          parentPhone: '',
          parentWechat: '',
        });
        fetchPlayers();
      } else {
        alert(data.error || '创建失败');
      }
    } catch (error) {
      console.error('创建学员失败:', error);
      alert('创建学员失败');
    }
  };

  const handleEditPlayer = (player: Player) => {
    setEditingPlayer(player);
    setFormData({
      name: player.name,
      gender: player.gender,
      birthDate: player.birthDate.split('T')[0],
      group: player.group,
      status: player.status,
      school: player.school || '',
      parentName: player.parentName || '',
      parentPhone: player.parentPhone || '',
      parentWechat: player.parentWechat || '',
    });
    setShowAddModal(true);
  };

  const handleUpdatePlayer = async () => {
    if (!editingPlayer || !formData.name || !formData.birthDate) {
      alert('请填写姓名和出生日期');
      return;
    }

    try {
      const response = await fetchWithAuth(`/api/players/${editingPlayer.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (data.success) {
        setShowAddModal(false);
        setEditingPlayer(null);
        setFormData({
          name: '',
          gender: 'male',
          birthDate: '',
          group: 'U10',
          status: 'training',
          school: '',
          parentName: '',
          parentPhone: '',
          parentWechat: '',
        });
        fetchPlayers();
      } else {
        alert(data.error || '更新失败');
      }
    } catch (error) {
      console.error('更新学员失败:', error);
      alert('更新学员失败');
    }
  };

  const handleDeletePlayer = async (id: string, name: string) => {
    if (!confirm(`确定要删除学员「${name}」吗？此操作不可恢复。`)) {
      return;
    }

    try {
      const response = await fetchWithAuth(`/api/players/${id}`, { method: 'DELETE' });
      const data = await response.json();

      if (data.success) {
        fetchPlayers();
      } else {
        alert(data.error || '删除失败');
      }
    } catch (error) {
      console.error('删除学员失败:', error);
      alert('删除学员失败');
    }
  };

  // 处理文件上传
  const handleFileUpload = async (file: File) => {
    const fileName = file.name.toLowerCase();
    if (
      !fileName.endsWith('.csv') &&
      !fileName.endsWith('.txt') &&
      !fileName.endsWith('.xlsx') &&
      !fileName.endsWith('.xls')
    ) {
      alert('请上传 CSV 或 Excel 格式的文件');
      return;
    }

    setImporting(true);
    try {
      const formData = new FormData();
      formData.append('file', file);

      const response = await fetch('/api/players/import', {
        method: 'POST',
        body: formData,
      });

      const data = await response.json();
      setImportResult(data);

      if (!data.success) {
        alert(data.error || '导入失败');
      }
    } catch (error) {
      console.error('导入失败:', error);
      setImportResult({
        success: false,
        total: 0,
        created: 0,
        failed: 0,
        message: '导入过程出错，请重试',
      });
    } finally {
      setImporting(false);
    }
  };

  // 计算统计数据
  const stats = useMemo(() => {
    return {
      total: players.length,
      training: players.filter((p) => p.status === 'training').length,
      trial: players.filter((p) => p.status === 'trial').length,
    };
  }, [players]);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link href="/" className="p-2 hover:bg-gray-100 rounded-lg">
                <ArrowLeft className="w-5 h-5 text-gray-600" />
              </Link>
              <div>
                <h1 className="text-xl font-bold text-gray-900">学员管理</h1>
                <p className="text-sm text-gray-500">
                  共 {stats.total} 名学员 · {stats.training} 在训 · {stats.trial} 试听
                </p>
              </div>
            </div>
            <button
              onClick={() => {
                setEditingPlayer(null);
                setFormData({
                  name: '',
                  gender: 'male',
                  birthDate: '',
                  group: 'U10',
                  status: 'training',
                  school: '',
                  parentName: '',
                  parentPhone: '',
                  parentWechat: '',
                });
                setShowAddModal(true);
              }}
              className="flex items-center gap-2 px-4 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg"
            >
              <Plus className="w-4 h-4" />
              添加学员
            </button>
            <a
              href="/api/export?type=players&format=excel"
              download
              className="flex items-center gap-2 px-4 py-2 border border-gray-300 hover:bg-gray-50 text-gray-700 rounded-lg"
            >
              <Download className="w-4 h-4" />
              导出
            </a>
            <button
              onClick={() => {
                setShowImportModal(true);
                setImportResult(null);
              }}
              className="flex items-center gap-2 px-4 py-2 border border-green-300 hover:bg-green-50 text-green-700 rounded-lg"
            >
              <Upload className="w-4 h-4" />
              批量导入
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-4 sm:py-6">
        {/* 搜索和筛选 - 移动端优化 */}
        <div className="space-y-3 sm:space-y-0 sm:flex sm:flex-wrap sm:gap-4 mb-4 sm:mb-6">
          {/* 搜索框 */}
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="text"
              placeholder="搜索学员姓名..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              className="w-full pl-10 pr-4 py-3 sm:py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent text-sm sm:text-base min-h-12"
            />
          </div>

          {/* 筛选条件 - 移动端横向滚动 */}
          <div className="flex gap-2 overflow-x-auto pb-2 sm:pb-0">
            <select
              value={groupFilter}
              onChange={(e) => setGroupFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm min-h-10 bg-white whitespace-nowrap"
            >
              {groups.map((g) => (
                <option key={g} value={g}>
                  {g === 'all' ? '全部分组' : g}
                </option>
              ))}
            </select>

            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg text-sm min-h-10 bg-white whitespace-nowrap"
            >
              {statuses.map((s) => (
                <option key={s.value} value={s.value}>
                  {s.label}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* 学员列表 */}
        {loading ? (
          <div className="text-center py-12">
            <div className="inline-block w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin" />
            <p className="mt-2 text-gray-500">加载中...</p>
          </div>
        ) : players.length === 0 ? (
          <div className="text-center py-12">
            <Users className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">暂无学员</h3>
            <p className="text-gray-500 mb-4">点击右上角添加学员开始管理</p>
          </div>
        ) : (
          <div className="space-y-3">
            {players.map((player) => (
              <PlayerCard
                key={player.id}
                player={player}
                onLongPress={(x, y, p) => {
                  setLongPressMenu({
                    show: true,
                    x,
                    y,
                    player: p,
                  });
                }}
                onEdit={handleEditPlayer}
                onDelete={handleDeletePlayer}
              />
            ))}
          </div>
        )}
      </main>

      <PageModals
        longPressMenu={longPressMenu}
        setLongPressMenu={setLongPressMenu}
        showAddModal={showAddModal}
        setShowAddModal={setShowAddModal}
        editingPlayer={editingPlayer}
        setEditingPlayer={setEditingPlayer}
        formData={formData}
        setFormData={setFormData}
        handleUpdatePlayer={handleUpdatePlayer}
        handleAddPlayer={handleAddPlayer}
        handleEditPlayer={handleEditPlayer}
        handleDeletePlayer={handleDeletePlayer}
        showImportModal={showImportModal}
        setShowImportModal={setShowImportModal}
        importResult={importResult}
        setImportResult={setImportResult}
        dragActive={dragActive}
        setDragActive={setDragActive}
        handleFileUpload={handleFileUpload}
        fetchPlayers={fetchPlayers}
      />
    </div>
  );
}

interface PlayerCardProps {
  player: Player;
  onLongPress: (clientX: number, clientY: number, player: Player) => void;
  onEdit: (player: Player) => void;
  onDelete: (id: string, name: string) => void;
}

function PlayerCard({ player, onLongPress, onEdit, onDelete }: PlayerCardProps) {
  const longPressTimer = useRef<NodeJS.Timeout | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    const touch = e.touches?.[0];
    if (!touch) return;
    longPressTimer.current = setTimeout(() => {
      onLongPress(touch.clientX, touch.clientY, player);
    }, 500);
  };

  const handleTouchEnd = () => {
    if (longPressTimer.current) {
      clearTimeout(longPressTimer.current);
      longPressTimer.current = null;
    }
  };

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    onLongPress(e.clientX, e.clientY, player);
  };

  return (
    <div
      className="bg-white rounded-xl p-4 sm:p-5 shadow-sm border border-gray-100 hover:shadow-md transition-all active:scale-95 cursor-pointer select-none"
      onClick={() => (window.location.href = `/players/${player.id}`)}
      onTouchStart={handleTouchStart}
      onTouchEnd={handleTouchEnd}
      onTouchMove={handleTouchEnd}
      onContextMenu={handleContextMenu}
    >
      {/* 移动端优化：头像 + 姓名 + 分组（一行） */}
      <div className="flex items-center gap-3 mb-3">
        {/* 头像 */}
        <div className="w-12 h-12 bg-orange-100 rounded-full flex items-center justify-center flex-shrink-0">
          <span className="text-xl sm:text-lg font-bold text-orange-600">
            {player.name.charAt(0)}
          </span>
        </div>

        {/* 姓名和标签 */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <h3 className="font-semibold text-gray-900 truncate text-base">{player.name}</h3>
            <span className={`text-xs px-2 py-0.5 rounded-full ${statusColors[player.status]}`}>
              {statusLabels[player.status]}
            </span>
            <span className="text-xs px-2 py-0.5 bg-gray-100 text-gray-600 rounded-full">
              {player.group}
            </span>
          </div>

          {/* 性别和年龄 */}
          <div className="flex items-center gap-3 text-sm text-gray-500 mt-1">
            <span>{player.gender === 'male' ? '男' : '女'}</span>
            <span>{player.age}岁</span>
            {player.team && <span className="text-orange-600 text-xs">{player.team.name}</span>}
          </div>
        </div>

        {/* 右侧：查看详情按钮 */}
        <Link
          href={`/players/${player.id}`}
          className="p-3 sm:p-2 hover:bg-gray-100 rounded-lg text-orange-600 active:bg-gray-200 transition-colors min-h-12 min-w-12 flex items-center justify-center flex-shrink-0"
          title="查看详情"
          onClick={(e) => e.stopPropagation()}
        >
          <ChevronRight className="w-5 h-5" />
        </Link>
      </div>

      {/* 次要信息：学校、家长电话 */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-xs text-gray-500 mb-3">
        {player.school && (
          <div className="flex items-center gap-1">
            <MapPin className="w-3 h-3 flex-shrink-0" />
            <span className="truncate">{player.school}</span>
          </div>
        )}
        {player.parentPhone?.trim() && (
          <div className="flex items-center gap-1">
            <Phone className="w-3 h-3 flex-shrink-0" />
            <span>{player.parentPhone}</span>
          </div>
        )}
      </div>

      {/* 统计信息和操作按钮 */}
      <div className="flex items-center justify-between pt-3 border-t border-gray-100">
        <div className="flex items-center gap-4 text-xs text-gray-400">
          <span>训练 {player.trainingCount} 次</span>
          <span>评估 {player.assessmentCount} 次</span>
        </div>

        {/* 移动端：编辑和删除按钮 */}
        <div className="flex items-center gap-1">
          <button
            onClick={(e) => {
              e.stopPropagation();
              onEdit(player);
            }}
            className="p-3 sm:p-2 hover:bg-gray-100 rounded-lg text-gray-400 active:bg-gray-200 transition-colors min-h-12 min-w-12 flex items-center justify-center"
            title="编辑"
          >
            <Edit2 className="w-4 h-4" />
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onDelete(player.id, player.name);
            }}
            className="p-3 sm:p-2 hover:bg-gray-100 rounded-lg text-red-400 active:bg-gray-200 transition-colors min-h-12 min-w-12 flex items-center justify-center"
            title="删除"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
}

// 将页面级的弹窗和菜单逻辑提取为内联组件
function PageModals({
  longPressMenu,
  setLongPressMenu,
  showAddModal,
  setShowAddModal,
  editingPlayer,
  setEditingPlayer,
  formData,
  setFormData,
  handleUpdatePlayer,
  handleAddPlayer,
  handleEditPlayer,
  handleDeletePlayer,
  showImportModal,
  setShowImportModal,
  importResult,
  setImportResult,
  dragActive,
  setDragActive,
  handleFileUpload,
  fetchPlayers,
}: {
  longPressMenu: {
    show: boolean;
    x: number;
    y: number;
    player: Player | null;
  };
  setLongPressMenu: React.Dispatch<
    React.SetStateAction<{
      show: boolean;
      x: number;
      y: number;
      player: Player | null;
    }>
  >;
  showAddModal: boolean;
  setShowAddModal: (v: boolean) => void;
  editingPlayer: Player | null;
  setEditingPlayer: (v: Player | null) => void;
  formData: {
    name: string;
    gender: string;
    birthDate: string;
    group: string;
    status: string;
    school: string;
    parentName: string;
    parentPhone: string;
    parentWechat: string;
  };
  setFormData: React.Dispatch<
    React.SetStateAction<{
      name: string;
      gender: string;
      birthDate: string;
      group: string;
      status: string;
      school: string;
      parentName: string;
      parentPhone: string;
      parentWechat: string;
    }>
  >;
  handleUpdatePlayer: () => void;
  handleAddPlayer: () => void;
  handleEditPlayer: (p: Player) => void;
  handleDeletePlayer: (id: string, name: string) => void;
  showImportModal: boolean;
  setShowImportModal: (v: boolean) => void;
  importResult: {
    success: boolean;
    total?: number;
    created?: number;
    failed?: number;
    message?: string;
    errors?: { row: number; message?: string; name?: string; error?: string; type?: string }[];
  } | null;
  setImportResult: (
    v: {
      success: boolean;
      total?: number;
      created?: number;
      failed?: number;
      message?: string;
      errors?: { row: number; message?: string; name?: string; error?: string; type?: string }[];
    } | null
  ) => void;
  dragActive: boolean;
  setDragActive: (v: boolean) => void;
  handleFileUpload: (f: File) => Promise<void>;
  fetchPlayers: () => void;
}) {
  return (
    <>
      {/* 长按快捷菜单 */}
      {longPressMenu.show && (
        <>
          <div
            className="fixed inset-0 bg-black/30 z-40"
            onClick={() => setLongPressMenu({ show: false, x: 0, y: 0, player: null })}
          />
          <div
            className="fixed bg-white rounded-xl shadow-xl p-2 z-50 min-w-[200px]"
            style={{
              left: Math.min(longPressMenu.x, window.innerWidth - 220),
              top: Math.min(longPressMenu.y, window.innerHeight - 200),
            }}
          >
            <button
              onClick={() => {
                if (longPressMenu.player?.parentPhone) {
                  window.location.href = `tel:${longPressMenu.player.parentPhone}`;
                }
                setLongPressMenu({ show: false, x: 0, y: 0, player: null });
              }}
              className="w-full flex items-center gap-3 px-3 py-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <Phone className="w-4 h-4 text-green-600" />
              <span className="text-sm">拨打电话</span>
            </button>
            <button
              onClick={() => {
                if (longPressMenu.player) {
                  handleEditPlayer(longPressMenu.player);
                }
                setLongPressMenu({ show: false, x: 0, y: 0, player: null });
              }}
              className="w-full flex items-center gap-3 px-3 py-2 hover:bg-gray-100 rounded-lg transition-colors"
            >
              <Edit2 className="w-4 h-4 text-blue-600" />
              <span className="text-sm">编辑学员</span>
            </button>
            <button
              onClick={() => {
                if (longPressMenu.player) {
                  handleDeletePlayer(longPressMenu.player.id, longPressMenu.player.name);
                }
                setLongPressMenu({ show: false, x: 0, y: 0, player: null });
              }}
              className="w-full flex items-center gap-3 px-3 py-2 hover:bg-gray-100 rounded-lg transition-colors text-red-600"
            >
              <Trash2 className="w-4 h-4" />
              <span className="text-sm">删除学员</span>
            </button>
          </div>
        </>
      )}

      {/* 添加/编辑学员弹窗 */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl max-w-lg w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-4 border-b border-gray-200 sticky top-0 bg-white">
              <h2 className="text-lg font-bold text-gray-900">
                {editingPlayer ? '编辑学员' : '添加新学员'}
              </h2>
              <button
                onClick={() => {
                  setShowAddModal(false);
                  setEditingPlayer(null);
                }}
                className="p-1 hover:bg-gray-100 rounded-lg"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            <div className="p-4 space-y-4">
              {/* 姓名 */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  姓名 <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="请输入学员姓名"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                />
              </div>

              {/* 出生日期 */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  出生日期 <span className="text-red-500">*</span>
                </label>
                <input
                  type="date"
                  value={formData.birthDate}
                  onChange={(e) => setFormData({ ...formData, birthDate: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
                />
              </div>

              {/* 性别和分组 */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">性别</label>
                  <select
                    value={formData.gender}
                    onChange={(e) => setFormData({ ...formData, gender: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    <option value="male">男</option>
                    <option value="female">女</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">分组</label>
                  <select
                    value={formData.group}
                    onChange={(e) => setFormData({ ...formData, group: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    <option value="U6">U6 (4-6岁)</option>
                    <option value="U8">U8 (6-8岁)</option>
                    <option value="U10">U10 (8-10岁)</option>
                    <option value="U12">U12 (10-12岁)</option>
                    <option value="U14">U14 (12-14岁)</option>
                  </select>
                </div>
              </div>

              {/* 状态和学校 */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">状态</label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  >
                    <option value="trial">试听中</option>
                    <option value="training">在训</option>
                    <option value="vacation">请假</option>
                    <option value="suspended">停课</option>
                    <option value="graduated">结业</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">学校</label>
                  <input
                    type="text"
                    value={formData.school}
                    onChange={(e) => setFormData({ ...formData, school: e.target.value })}
                    placeholder="所在学校"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                  />
                </div>
              </div>

              {/* 家长信息 */}
              <div className="border-t border-gray-200 pt-4">
                <h3 className="text-sm font-medium text-gray-700 mb-3">家长联系方式</h3>
                <div className="space-y-3">
                  <div>
                    <label className="block text-sm text-gray-500 mb-1">家长姓名</label>
                    <input
                      type="text"
                      value={formData.parentName}
                      onChange={(e) => setFormData({ ...formData, parentName: e.target.value })}
                      placeholder="请输入家长姓名"
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm text-gray-500 mb-1">联系电话</label>
                      <input
                        type="tel"
                        value={formData.parentPhone}
                        onChange={(e) => setFormData({ ...formData, parentPhone: e.target.value })}
                        placeholder="手机号码"
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                      />
                    </div>
                    <div>
                      <label className="block text-sm text-gray-500 mb-1">微信</label>
                      <input
                        type="text"
                        value={formData.parentWechat}
                        onChange={(e) => setFormData({ ...formData, parentWechat: e.target.value })}
                        placeholder="微信号"
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* 操作按钮 */}
              <div className="flex gap-2 pt-2">
                <button
                  onClick={() => {
                    setShowAddModal(false);
                    setEditingPlayer(null);
                  }}
                  className="flex-1 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
                >
                  取消
                </button>
                <button
                  onClick={editingPlayer ? handleUpdatePlayer : handleAddPlayer}
                  className="flex-1 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg"
                >
                  {editingPlayer ? '保存修改' : '添加学员'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* 批量导入弹窗 */}
      {showImportModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-4 border-b border-gray-200 sticky top-0 bg-white">
              <h2 className="text-lg font-bold text-gray-900">批量导入学员</h2>
              <button
                onClick={() => {
                  setShowImportModal(false);
                  setImportResult(null);
                }}
                className="p-1 hover:bg-gray-100 rounded-lg"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            <div className="p-4">
              {!importResult ? (
                <>
                  {/* 下载模板 */}
                  <div className="mb-4 p-4 bg-gray-50 rounded-lg">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-3">
                        <FileSpreadsheet className="w-8 h-8 text-green-600" />
                        <div>
                          <p className="font-medium text-gray-900">学员导入模板</p>
                          <p className="text-sm text-gray-500">
                            支持 CSV、XLSX 格式，必填项：姓名、出生日期
                          </p>
                        </div>
                      </div>
                      <a
                        href="/api/players/import"
                        download="player_import_template.csv"
                        className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm"
                      >
                        下载模板
                      </a>
                    </div>
                  </div>

                  {/* 文件上传 */}
                  <div
                    className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors ${
                      dragActive
                        ? 'border-green-500 bg-green-50'
                        : 'border-gray-300 hover:border-green-400'
                    }`}
                    onDragOver={(e) => {
                      e.preventDefault();
                      setDragActive(true);
                    }}
                    onDragLeave={() => setDragActive(false)}
                    onDrop={async (e) => {
                      e.preventDefault();
                      setDragActive(false);
                      const file = e.dataTransfer.files[0];
                      if (file) await handleFileUpload(file);
                    }}
                  >
                    <Upload
                      className={`w-12 h-12 mx-auto mb-3 ${dragActive ? 'text-green-500' : 'text-gray-400'}`}
                    />
                    <p className="text-gray-700 mb-2">
                      拖拽 CSV/XLSX 文件到此处，或
                      <label className="text-green-600 hover:text-green-700 cursor-pointer mx-1">
                        点击选择文件
                        <input
                          type="file"
                          accept=".csv,.txt,.xlsx,.xls"
                          className="hidden"
                          onChange={(e) => {
                            const file = e.target.files?.[0];
                            if (file) handleFileUpload(file);
                          }}
                        />
                      </label>
                    </p>
                    <p className="text-sm text-gray-500">支持 .csv, .xlsx, .xls 格式</p>
                  </div>

                  {/* 导入说明 */}
                  <div className="mt-4 p-4 bg-blue-50 rounded-lg">
                    <h4 className="font-medium text-blue-900 mb-2">导入说明</h4>
                    <ul className="text-sm text-blue-700 space-y-1">
                      <li>• 文件格式：CSV（逗号分隔值）或 Excel（.xlsx/.xls）</li>
                      <li>• 必填字段：姓名、出生日期</li>
                      <li>
                        •
                        可选字段：性别（男/女）、分组（U6/U8/U10/U12/U14）、状态、学校、家长姓名、联系电话、微信
                      </li>
                      <li>• 出生日期格式：YYYY-MM-DD（如 2018-05-01）</li>
                      <li>• 分组和状态会自动转换，如"在训"→"training"</li>
                    </ul>
                  </div>
                </>
              ) : (
                /* 导入结果 */
                <div className="space-y-4">
                  {/* 结果摘要 */}
                  <div
                    className={`p-4 rounded-lg ${importResult.success ? 'bg-green-50' : 'bg-red-50'}`}
                  >
                    <div className="flex items-center gap-3">
                      {importResult.success ? (
                        <CheckCircle className="w-8 h-8 text-green-600" />
                      ) : (
                        <AlertCircle className="w-8 h-8 text-red-600" />
                      )}
                      <div>
                        <p
                          className={`font-medium ${importResult.success ? 'text-green-900' : 'text-red-900'}`}
                        >
                          {importResult.message ||
                            (importResult.success
                              ? `成功导入 ${importResult.created} 名学员`
                              : '导入失败')}
                        </p>
                        <p className="text-sm text-gray-600">
                          总计 {importResult.total} 行，成功 {importResult.created} 行，失败{' '}
                          {importResult.failed} 行
                        </p>
                      </div>
                    </div>
                  </div>

                  {/* 失败详情 */}
                  {importResult.errors && importResult.errors.length > 0 && (
                    <div className="p-4 border border-gray-200 rounded-lg">
                      <h4 className="font-medium text-gray-900 mb-3">失败详情</h4>
                      <div className="max-h-48 overflow-y-auto space-y-2">
                        {importResult.errors.map((err, idx) => (
                          <div key={idx} className="flex items-start gap-2 text-sm">
                            <span className="text-gray-400">第{err.row}行:</span>
                            <span className="text-red-600">
                              {err.name && `${err.name} - `}
                              {err.message || err.error}
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* 操作按钮 */}
                  <div className="flex gap-2">
                    <button
                      onClick={() => {
                        setImportResult(null);
                      }}
                      className="flex-1 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
                    >
                      继续导入
                    </button>
                    <button
                      onClick={() => {
                        setShowImportModal(false);
                        setImportResult(null);
                        fetchPlayers();
                      }}
                      className="flex-1 py-2 bg-orange-500 hover:bg-orange-600 text-white rounded-lg"
                    >
                      完成
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  Save,
  Plus,
  History,
  Eye,
  Trash2,
  CheckCircle,
  XCircle,
  Copy,
  ChevronDown,
  ChevronUp,
  FileText,
  Zap,
  AlertTriangle,
} from 'lucide-react';

type PromptTemplate = {
  id: string;
  name: string;
  key: string;
  description: string | null;
  content: string;
  version: number;
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
  totalVersions?: number;
};

export default function PromptsPage() {
  const router = useRouter();
  const [templates, setTemplates] = useState<PromptTemplate[]>([]);
  const [selectedKey, setSelectedKey] = useState<string | null>(null);
  const [versions, setVersions] = useState<PromptTemplate[]>([]);
  const [editingContent, setEditingContent] = useState('');
  const [editDescription, setEditDescription] = useState('');
  const [showEditor, setShowEditor] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [showDiff, setShowDiff] = useState(false);
  const [diffContent, setDiffContent] = useState('');
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [previewTemplate, setPreviewTemplate] = useState<PromptTemplate | null>(null);
  const [showPreview, setShowPreview] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error'; message: string } | null>(null);
  const [deleting, setDeleting] = useState<string | null>(null);

  const showToast = (type: 'success' | 'error', message: string) => {
    setToast({ type, message });
    setTimeout(() => setToast(null), 3000);
  };

  const loadTemplates = useCallback(async () => {
    try {
      const res = await fetchWithAuth('/api/prompts');
      const data = await res.json();
      if (data.success) {
        setTemplates(data.templates);
      }
    } catch (error) {
      console.error('加载失败:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  const loadVersions = useCallback(async (key: string) => {
    try {
      const res = await fetchWithAuth(`/api/prompts?key=${key}&all=true`);
      const data = await res.json();
      if (data.success) {
        setVersions(data.templates);
      }
    } catch (error) {
      console.error('加载版本失败:', error);
    }
  }, []);

  useEffect(() => {
    loadTemplates();
  }, [loadTemplates]);

  const handleSelectTemplate = (template: PromptTemplate) => {
    setSelectedKey(template.key);
    setShowHistory(true);
    setShowEditor(false);
    setShowDiff(false);
    setShowPreview(false);
    loadVersions(template.key);
  };

  const handleEdit = (template: PromptTemplate) => {
    setEditingContent(template.content);
    setEditDescription(template.description || '');
    setShowEditor(true);
    setShowHistory(false);
    setShowDiff(false);
  };

  const handlePreview = (template: PromptTemplate) => {
    setPreviewTemplate(template);
    setShowPreview(true);
  };

  const handleDiff = (template: PromptTemplate) => {
    setDiffContent(template.content);
    setShowDiff(true);
  };

  const handleSave = async () => {
    if (!selectedKey || !editingContent.trim()) {
      showToast('error', 'Prompt 内容不能为空');
      return;
    }

    // 找到当前版本的 ID
    const current = versions.find((v) => v.isActive) || versions[0];
    if (!current) return;

    setSaving(true);
    try {
      const res = await fetchWithAuth(`/api/prompts/${current.id}`, {
        method: 'PATCH',
        body: JSON.stringify({
          content: editingContent,
          description: editDescription,
        }),
      });
      const data = await res.json();
      if (data.success) {
        showToast('success', `已创建 v${data.template.version} 新版本`);
        setShowEditor(false);
        await loadTemplates();
        await loadVersions(selectedKey);
      } else {
        showToast('error', data.error || '保存失败');
      }
    } catch (error) {
      showToast('error', '保存失败');
    } finally {
      setSaving(false);
    }
  };

  const handleActivate = async (template: PromptTemplate) => {
    if (!confirm(`确定要激活 v${template.version} 版本吗？`)) return;

    try {
      const res = await fetchWithAuth(`/api/prompts/${template.id}`, {
        method: 'POST',
      });
      const data = await res.json();
      if (data.success) {
        showToast('success', `v${template.version} 已激活`);
        await loadTemplates();
        await loadVersions(selectedKey!);
      } else {
        showToast('error', data.error || '激活失败');
      }
    } catch (error) {
      showToast('error', '激活失败');
    }
  };

  const handleDelete = async (template: PromptTemplate) => {
    if (!confirm(`确定要删除 v${template.version} 版本吗？此操作不可撤销。`)) return;

    setDeleting(template.id);
    try {
      const res = await fetchWithAuth(`/api/prompts/${template.id}`, {
        method: 'DELETE',
      });
      const data = await res.json();
      if (data.success) {
        showToast('success', '已删除');
        await loadTemplates();
        await loadVersions(selectedKey!);
      } else {
        showToast('error', data.error || '删除失败');
      }
    } catch (error) {
      showToast('error', '删除失败');
    } finally {
      setDeleting(null);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    showToast('success', '已复制到剪贴板');
  };

  // 统计字符数和行数
  const getContentStats = (content: string) => {
    const chars = content.length;
    const lines = content.split('\n').length;
    return `${chars} 字符 / ${lines} 行`;
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-gray-500">加载中...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Toast */}
      {toast && (
        <div
          className={`fixed top-4 right-4 z-50 px-4 py-3 rounded-lg shadow-lg text-white text-sm font-medium ${
            toast.type === 'success' ? 'bg-green-500' : 'bg-red-500'
          }`}
        >
          {toast.type === 'success' ? (
            <CheckCircle className="w-4 h-4 inline mr-1" />
          ) : (
            <XCircle className="w-4 h-4 inline mr-1" />
          )}
          {toast.message}
        </div>
      )}

      {/* Header */}
      <header className="bg-gradient-to-r from-violet-600 to-purple-600 text-white">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center gap-4">
          <button
            onClick={() => router.push('/')}
            className="p-2 hover:bg-white/10 rounded-lg transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <div>
            <h1 className="text-xl font-bold flex items-center gap-2">
              <FileText className="w-5 h-5" />
              Prompt 管理
            </h1>
            <p className="text-purple-200 text-sm">
              管理和编辑 AI 教案生成的提示词模板，支持版本控制
            </p>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6">
        {/* 模板列表 */}
        {!selectedKey && (
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-900">Prompt 模板</h2>
            {templates.length === 0 ? (
              <div className="bg-white rounded-xl p-8 text-center text-gray-500">
                <FileText className="w-12 h-12 mx-auto mb-3 text-gray-300" />
                <p>暂无 Prompt 模板</p>
                <p className="text-sm mt-1">首次部署时会自动导入当前 Prompt</p>
              </div>
            ) : (
              <div className="grid gap-4 md:grid-cols-2">
                {templates.map((template) => (
                  <div
                    key={template.id}
                    className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow cursor-pointer"
                    onClick={() => handleSelectTemplate(template)}
                  >
                    <div className="flex items-start justify-between mb-3">
                      <div className="flex items-center gap-2">
                        <div className="w-10 h-10 bg-gradient-to-r from-violet-500 to-purple-500 rounded-lg flex items-center justify-center">
                          <Zap className="w-5 h-5 text-white" />
                        </div>
                        <div>
                          <h3 className="font-semibold text-gray-900">{template.name}</h3>
                          <p className="text-xs text-gray-500 font-mono">{template.key}</p>
                        </div>
                      </div>
                      {template.isActive ? (
                        <span className="px-2 py-1 bg-green-100 text-green-700 text-xs rounded-full font-medium flex items-center gap-1">
                          <CheckCircle className="w-3 h-3" /> 使用中
                        </span>
                      ) : (
                        <span className="px-2 py-1 bg-gray-100 text-gray-500 text-xs rounded-full font-medium">
                          未激活
                        </span>
                      )}
                    </div>
                    {template.description && (
                      <p className="text-sm text-gray-600 mb-3">{template.description}</p>
                    )}
                    <div className="flex items-center justify-between text-xs text-gray-400">
                      <span>v{template.version}</span>
                      <span>{getContentStats(template.content)}</span>
                      {template.totalVersions && template.totalVersions > 1 && (
                        <span className="text-violet-500 font-medium">
                          {template.totalVersions} 个版本
                        </span>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* 版本历史 */}
        {selectedKey && showHistory && !showEditor && !showPreview && (
          <div>
            <div className="flex items-center justify-between mb-4">
              <button
                onClick={() => {
                  setSelectedKey(null);
                  setVersions([]);
                }}
                className="text-sm text-violet-600 hover:text-violet-800 flex items-center gap-1"
              >
                <ArrowLeft className="w-4 h-4" /> 返回列表
              </button>
              <button
                onClick={() => {
                  const current = versions.find((v) => v.isActive) || versions[0];
                  if (current) handleEdit(current);
                }}
                className="px-4 py-2 bg-violet-600 text-white rounded-lg text-sm font-medium hover:bg-violet-700 flex items-center gap-1"
              >
                <Plus className="w-4 h-4" /> 新建版本
              </button>
            </div>
            <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
              <History className="w-5 h-5" />
              版本历史
              <span className="text-sm font-normal text-gray-500">({versions.length} 个版本)</span>
            </h2>
            <div className="space-y-3">
              {versions.map((v, idx) => (
                <div
                  key={v.id}
                  className={`bg-white rounded-xl p-5 shadow-sm border ${
                    v.isActive ? 'border-green-200 bg-green-50/30' : 'border-gray-100'
                  }`}
                >
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-3 mb-2">
                        <span className="font-bold text-gray-900">v{v.version}</span>
                        {v.isActive && (
                          <span className="px-2 py-0.5 bg-green-100 text-green-700 text-xs rounded-full font-medium flex items-center gap-1">
                            <CheckCircle className="w-3 h-3" /> 使用中
                          </span>
                        )}
                        <span className="text-xs text-gray-400">
                          {new Date(v.updatedAt).toLocaleString('zh-CN')}
                        </span>
                      </div>
                      {v.description && (
                        <p className="text-sm text-gray-600 mb-2">{v.description}</p>
                      )}
                      <p className="text-xs text-gray-400">{getContentStats(v.content)}</p>
                    </div>
                    <div className="flex items-center gap-2 ml-4">
                      <button
                        onClick={() => handlePreview(v)}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="预览"
                      >
                        <Eye className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => handleEdit(v)}
                        className="p-2 text-gray-400 hover:text-violet-600 hover:bg-violet-50 rounded-lg transition-colors"
                        title="基于此版本编辑"
                      >
                        <Copy className="w-4 h-4" />
                      </button>
                      {!v.isActive && (
                        <button
                          onClick={() => handleActivate(v)}
                          className="p-2 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                          title="激活此版本"
                        >
                          <CheckCircle className="w-4 h-4" />
                        </button>
                      )}
                      {versions.length > 1 && !v.isActive && (
                        <button
                          onClick={() => handleDelete(v)}
                          disabled={deleting === v.id}
                          className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
                          title="删除此版本"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* 编辑器 */}
        {showEditor && (
          <div>
            <div className="flex items-center justify-between mb-4">
              <button
                onClick={() => {
                  setShowEditor(false);
                  setShowHistory(true);
                }}
                className="text-sm text-violet-600 hover:text-violet-800 flex items-center gap-1"
              >
                <ArrowLeft className="w-4 h-4" /> 返回版本历史
              </button>
              <div className="flex items-center gap-3">
                <span className="text-xs text-gray-400">{getContentStats(editingContent)}</span>
                <button
                  onClick={handleSave}
                  disabled={saving || !editingContent.trim()}
                  className="px-4 py-2 bg-violet-600 text-white rounded-lg text-sm font-medium hover:bg-violet-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1"
                >
                  <Save className="w-4 h-4" />
                  {saving ? '保存中...' : '保存新版本'}
                </button>
              </div>
            </div>

            {/* 版本说明 */}
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-1">
                版本说明（可选）
              </label>
              <input
                type="text"
                value={editDescription}
                onChange={(e) => setEditDescription(e.target.value)}
                placeholder="描述本次修改了什么，如：强化战术库，新增反跑配合..."
                className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-violet-500"
              />
            </div>

            {/* 提示 */}
            <div className="mb-4 p-3 bg-amber-50 border border-amber-200 rounded-lg flex items-start gap-2">
              <AlertTriangle className="w-4 h-4 text-amber-500 mt-0.5 flex-shrink-0" />
              <p className="text-sm text-amber-800">
                保存后将创建一个新版本，当前使用中的版本不受影响。保存后可以切换到版本历史页面激活新版本。
              </p>
            </div>

            {/* 编辑区域 */}
            <textarea
              value={editingContent}
              onChange={(e) => setEditingContent(e.target.value)}
              className="w-full h-[70vh] px-4 py-3 border border-gray-200 rounded-xl text-sm font-mono leading-relaxed focus:outline-none focus:ring-2 focus:ring-violet-500 bg-white resize-none"
              placeholder="在这里编辑 Prompt 内容..."
              spellCheck={false}
            />
          </div>
        )}

        {/* 预览 */}
        {showPreview && previewTemplate && (
          <div>
            <div className="flex items-center justify-between mb-4">
              <button
                onClick={() => {
                  setShowPreview(false);
                  if (selectedKey) setShowHistory(true);
                }}
                className="text-sm text-violet-600 hover:text-violet-800 flex items-center gap-1"
              >
                <ArrowLeft className="w-4 h-4" /> 返回
              </button>
              <div className="flex items-center gap-2">
                <span className="font-bold text-gray-900">v{previewTemplate.version}</span>
                {previewTemplate.isActive && (
                  <span className="px-2 py-0.5 bg-green-100 text-green-700 text-xs rounded-full font-medium">
                    使用中
                  </span>
                )}
                <button
                  onClick={() => handleCopy(previewTemplate.content)}
                  className="px-3 py-1.5 text-sm text-gray-600 hover:text-violet-600 hover:bg-violet-50 rounded-lg flex items-center gap-1"
                >
                  <Copy className="w-4 h-4" /> 复制
                </button>
              </div>
            </div>
            <div className="bg-white rounded-xl border border-gray-200 p-6">
              <pre className="whitespace-pre-wrap text-sm font-mono leading-relaxed text-gray-800 max-h-[75vh] overflow-y-auto">
                {previewTemplate.content}
              </pre>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { fetchWithAuth } from '@/lib/auth';
import {
  ArrowLeft,
  Search,
  Filter,
  Calendar,
  Users,
  Star,
  CheckCircle2,
  XCircle,
  Clock,
  ChevronDown,
  ChevronRight,
  ClipboardList,
  Download,
} from 'lucide-react';

type TrainingRecord = {
  id: string;
  playerId?: string;
  playerName?: string;
  playerGroup?: string;
  planId?: string;
  planTitle?: string;
  planDate?: string;
  planTheme?: string;
  attendance: string;
  performance?: number;
  feedback?: string;
  recordedAt: string;
};

// 按教案分组
type GroupedRecords = {
  planId: string;
  planTitle: string;
  planDate: string;
  planTheme?: string;
  records: TrainingRecord[];
};

const attendanceConfig: Record<
  string,
  { label: string; color: string; icon: typeof CheckCircle2 }
> = {
  present: { label: '出勤', color: 'text-green-600 bg-green-50', icon: CheckCircle2 },
  late: { label: '迟到', color: 'text-yellow-600 bg-yellow-50', icon: Clock },
  absent: { label: '缺勤', color: 'text-red-600 bg-red-50', icon: XCircle },
};

export default function RecordsPage() {
  const [records, setRecords] = useState<TrainingRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedPlan, setExpandedPlan] = useState<string | null>(null);
  const [filterAttendance, setFilterAttendance] = useState<string>('all');

  const fetchRecords = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetchWithAuth('/api/records?limit=200');
      const data = await res.json();
      if (data.success) {
        setRecords(data.records || []);
        // 默认展开第一个教案
        const firstPlanId = data.records?.[0]?.planId;
        if (firstPlanId) setExpandedPlan(firstPlanId);
      }
    } catch (error) {
      console.error('获取训练记录失败:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchRecords();
  }, [fetchRecords]);

  // 按教案分组
  const grouped = records
    .filter((r) => {
      if (filterAttendance !== 'all' && r.attendance !== filterAttendance) return false;
      if (searchTerm) {
        const term = searchTerm.toLowerCase();
        return (
          (r.playerName || '').toLowerCase().includes(term) ||
          (r.planTitle || '').toLowerCase().includes(term) ||
          (r.planTheme || '').toLowerCase().includes(term) ||
          (r.feedback || '').toLowerCase().includes(term)
        );
      }
      return true;
    })
    .reduce<GroupedRecords[]>((acc, r) => {
      const planId = r.planId || 'unknown';
      const existing = acc.find((g) => g.planId === planId);
      if (existing) {
        existing.records.push(r);
      } else {
        acc.push({
          planId,
          planTitle: r.planTitle || '训练课',
          planDate: r.planDate || r.recordedAt,
          planTheme: r.planTheme,
          records: [r],
        });
      }
      return acc;
    }, []);

  // 统计
  const totalRecords = records.length;
  const presentCount = records.filter((r) => r.attendance === 'present').length;
  const lateCount = records.filter((r) => r.attendance === 'late').length;
  const absentCount = records.filter((r) => r.attendance === 'absent').length;
  const avgPerformance =
    records.filter((r) => r.performance && r.performance > 0).length > 0
      ? (
          records
            .filter((r) => r.performance && r.performance > 0)
            .reduce((sum, r) => sum + (r.performance || 0), 0) /
          records.filter((r) => r.performance && r.performance > 0).length
        ).toFixed(1)
      : '--';

  // 导出CSV
  function handleExportCSV() {
    const header = [
      '训练日期',
      '教案名称',
      '训练主题',
      '学员姓名',
      '组别',
      '出勤状态',
      '表现评分',
      '教练反馈',
      '记录时间',
    ];
    const rows = records.map((r) => [
      r.planDate ? new Date(r.planDate).toLocaleDateString('zh-CN') : '',
      r.planTitle || '',
      r.planTheme || '',
      r.playerName || '',
      r.playerGroup || '',
      attendanceConfig[r.attendance]?.label || r.attendance,
      r.performance ? String(r.performance) : '',
      r.feedback || '',
      r.recordedAt ? new Date(r.recordedAt).toLocaleString('zh-CN') : '',
    ]);

    // BOM + CSV内容，确保中文在Excel中正确显示
    const bom = '\uFEFF';
    const csv =
      bom +
      [header, ...rows]
        .map((row) => row.map((cell) => `"${cell.replace(/"/g, '""')}"`).join(','))
        .join('\n');

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `训练记录_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 头部 */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 py-4">
          <div className="flex items-center gap-4">
            <Link href="/" className="p-2 hover:bg-gray-100 rounded-lg">
              <ArrowLeft className="w-5 h-5 text-gray-600" />
            </Link>
            <div className="flex-1">
              <h1 className="text-xl font-bold text-gray-900">训练记录</h1>
              <p className="text-sm text-gray-500">共 {totalRecords} 条记录</p>
            </div>
            <button
              onClick={handleExportCSV}
              className="flex items-center gap-1.5 px-3 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors text-sm font-medium shadow-sm"
            >
              <Download className="w-4 h-4" />
              导出
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-4 space-y-4">
        {/* 统计概览 */}
        <div className="grid grid-cols-4 gap-3">
          <div className="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center">
            <div className="text-xl font-bold text-blue-600">{presentCount}</div>
            <div className="text-xs text-gray-500 mt-0.5">出勤</div>
          </div>
          <div className="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center">
            <div className="text-xl font-bold text-yellow-600">{lateCount}</div>
            <div className="text-xs text-gray-500 mt-0.5">迟到</div>
          </div>
          <div className="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center">
            <div className="text-xl font-bold text-red-600">{absentCount}</div>
            <div className="text-xs text-gray-500 mt-0.5">缺勤</div>
          </div>
          <div className="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center">
            <div className="text-xl font-bold text-orange-600">{avgPerformance}</div>
            <div className="text-xs text-gray-500 mt-0.5">平均评分</div>
          </div>
        </div>

        {/* 搜索和筛选 */}
        <div className="flex gap-2">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="搜索学员、教案..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-3 py-2.5 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-500 bg-white"
            />
          </div>
          <select
            value={filterAttendance}
            onChange={(e) => setFilterAttendance(e.target.value)}
            className="px-3 py-2.5 border border-gray-200 rounded-lg text-sm bg-white focus:outline-none focus:ring-2 focus:ring-orange-500"
          >
            <option value="all">全部</option>
            <option value="present">出勤</option>
            <option value="late">迟到</option>
            <option value="absent">缺勤</option>
          </select>
        </div>

        {/* 记录列表（按教案分组） */}
        {loading ? (
          <div className="flex items-center justify-center py-20">
            <div className="inline-block w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin" />
          </div>
        ) : grouped.length === 0 ? (
          <div className="text-center py-16">
            <ClipboardList className="w-16 h-16 text-gray-200 mx-auto mb-4" />
            <p className="text-gray-500 mb-2">
              {searchTerm || filterAttendance !== 'all' ? '没有匹配的记录' : '暂无训练记录'}
            </p>
            {!searchTerm && filterAttendance === 'all' && (
              <Link href="/plan/new" className="text-orange-500 hover:underline text-sm">
                创建第一个教案 →
              </Link>
            )}
          </div>
        ) : (
          <div className="space-y-3">
            {grouped.map((group) => {
              const isExpanded = expandedPlan === group.planId;
              const groupPresent = group.records.filter((r) => r.attendance === 'present').length;
              const groupLate = group.records.filter((r) => r.attendance === 'late').length;
              const groupAbsent = group.records.filter((r) => r.attendance === 'absent').length;
              const groupScored = group.records.filter((r) => r.performance && r.performance > 0);
              const groupAvg =
                groupScored.length > 0
                  ? (
                      groupScored.reduce((s, r) => s + (r.performance || 0), 0) / groupScored.length
                    ).toFixed(1)
                  : '--';

              return (
                <div
                  key={group.planId}
                  className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden"
                >
                  {/* 教案头部（可展开） */}
                  <button
                    onClick={() => setExpandedPlan(isExpanded ? null : group.planId)}
                    className="w-full flex items-center gap-3 p-4 text-left hover:bg-gray-50 transition-colors"
                  >
                    {isExpanded ? (
                      <ChevronDown className="w-4 h-4 text-gray-400 shrink-0" />
                    ) : (
                      <ChevronRight className="w-4 h-4 text-gray-400 shrink-0" />
                    )}
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-gray-900 truncate">{group.planTitle}</div>
                      <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                        <span className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          {new Date(group.planDate).toLocaleDateString('zh-CN')}
                        </span>
                        {group.planTheme && <span>· {group.planTheme}</span>}
                      </div>
                    </div>
                    <div className="flex items-center gap-2 shrink-0">
                      <span className="text-xs text-green-600">{groupPresent}到</span>
                      {groupLate > 0 && (
                        <span className="text-xs text-yellow-600">{groupLate}迟</span>
                      )}
                      {groupAbsent > 0 && (
                        <span className="text-xs text-red-600">{groupAbsent}缺</span>
                      )}
                      <span className="text-xs font-medium text-gray-700">
                        {group.records.length}人
                      </span>
                    </div>
                  </button>

                  {/* 展开后的记录列表 */}
                  {isExpanded && (
                    <div className="border-t border-gray-100">
                      {group.records.map((record) => {
                        const attConfig =
                          attendanceConfig[record.attendance] || attendanceConfig.present;
                        const AttIcon = attConfig.icon;
                        return (
                          <div
                            key={record.id}
                            className="flex items-start gap-3 px-4 py-3 hover:bg-gray-50 border-b border-gray-50 last:border-b-0"
                          >
                            {/* 学员头像 */}
                            <div className="w-9 h-9 bg-gray-100 rounded-full flex items-center justify-center shrink-0 text-sm font-medium text-gray-600">
                              {(record.playerName || '?').charAt(0)}
                            </div>

                            {/* 学员信息 */}
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2">
                                <span className="text-sm font-medium text-gray-900">
                                  {record.playerName || '未知学员'}
                                </span>
                                {record.playerGroup && (
                                  <span className="text-xs px-1.5 py-0.5 bg-gray-100 text-gray-500 rounded">
                                    {record.playerGroup}
                                  </span>
                                )}
                                <span
                                  className={`text-xs px-1.5 py-0.5 rounded flex items-center gap-1 ${attConfig.color}`}
                                >
                                  <AttIcon className="w-3 h-3" />
                                  {attConfig.label}
                                </span>
                              </div>
                              {record.feedback && (
                                <p className="text-xs text-gray-500 mt-1 line-clamp-2">
                                  {record.feedback}
                                </p>
                              )}
                            </div>

                            {/* 评分 */}
                            <div className="text-right shrink-0">
                              {record.performance && record.performance > 0 ? (
                                <div className="flex items-center gap-1">
                                  <Star className="w-3.5 h-3.5 text-yellow-400 fill-yellow-400" />
                                  <span className="text-sm font-semibold text-gray-700">
                                    {record.performance}
                                  </span>
                                </div>
                              ) : (
                                <span className="text-xs text-gray-300">未评</span>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </main>
    </div>
  );
}

